/* ---- Group drag-follow state ----
 * When the user click-drags a single group member directly (rather than
 * grabbing the Transformer's bounding box), Konva moves only that one
 * node — the siblings + group rect would otherwise stay put.
 * `_groupDragSnapshot` lets us shift them by the same delta on every
 * dragmove. Same pattern as `updateShading()` on a video device's
 * `#fov~id` coverage node — that follower runs from the device's own
 * `dragmove` handler. We snapshot start positions on the first dragmove
 * (lazy init) and apply absolute deltas, so the math stays correct
 * even if other handlers also shift positions. */
let _groupDragSnapshot = null;

/* Return every CustomItem rect whose members ALL belong to the given Group.
 * Used by the Group drag-follow + form-update paths so a Group drag/rotate
 * also carries any "fully contained" CustomItem rects with it.
 *
 * Why "all members" and not "any member"? A CustomItem whose members are
 * split across multiple Groups (uncommon, but legal — VRC Groups and VRC
 * CustomItems are independent flat memberships) is no longer rigid with
 * any single Group during that Group's drag: only some of its members
 * move. Shifting the rect by the dragged Group's delta would visually
 * detach it from the un-moved members. So we move the rect only when the
 * whole CustomItem rides with the Group — which is the user-visible
 * "3 CustomItems inside 1 Group" pattern that surfaced this gap.
 *
 * Note: the Transformer-drag path doesn't need this — `expandSelectionForGroups()`
 * already adds every overlapping CustomItem rect to `tr.nodes()`, and Konva
 * then moves them natively. This helper exists for the two paths Konva
 * doesn't cover: member-direct drag (`followGroupDragFromMember`) and the
 * form-update path (`updateGroupItem`). */
function getCustomItemRectsAllInGroup(groupId) {
    if (!groupId || typeof groupCustomItemRects === 'undefined' || !groupCustomItemRects) return [];
    const result = [];
    groupCustomItemRects.getChildren().forEach(rect => {
        const ciId = rect.data_customItemId;
        if (!ciId) return;
        const members = getCustomItemMemberNodes(ciId);
        if (members.length === 0) return;
        if (members.every(m => m.data_groupId === groupId)) result.push(rect);
    });
    return result;
}

/* Snapshot every group sibling + the Group rect's start position so the
 * follower can shift them in lock-step with the dragged member. MUST be
 * called from `dragstart` (or earlier), not `dragmove` — by the first
 * dragmove `target.x()` has already advanced a few pixels past where it
 * was before the user started moving the mouse. Snapshotting at dragmove
 * time bakes that offset into `startPos.x` and the rect/siblings end up
 * drifting behind the dragged member by exactly the first-dragmove jump
 * (visible as the purple Group rect parting from its chairs in the
 * screenshot). Capturing in dragstart pins startPos to the true pre-drag
 * position so `dx = target.x() - startPos.x` is accurate from the very
 * first dragmove onward. Safe to call multiple times for the same drag —
 * later calls re-snapshot from the (still-correct) current positions. */
function beginGroupDragFollow(target) {
    if (!target || !target.data_groupId) return;
    if (tr.isDragging()) { _groupDragSnapshot = null; return; }
    _groupDragSnapshot = {
        groupId:  target.data_groupId,
        target:   target,
        startPos: { x: target.x(), y: target.y() },
        others:   new Map(),
    };
    getGroupMemberNodes(target.data_groupId).forEach(member => {
        if (member === target) return;
        _groupDragSnapshot.others.set(member, { x: member.x(), y: member.y() });
    });
    if (groupGroupRects) {
        const rectNode = groupGroupRects.find(n => n.data_groupId === target.data_groupId)[0];
        if (rectNode && rectNode !== target) {
            _groupDragSnapshot.others.set(rectNode, { x: rectNode.x(), y: rectNode.y() });
        }
    }
    /* Also pull in CustomItem rects whose members all belong to this Group
     * — without this, dragging the Group leaves the "fully-contained"
     * CustomItem rects behind. The CustomItem follower only handles the
     * dragged item's own CustomItem rect, so siblings B/C in a "3 CustomItems
     * in 1 Group" layout would otherwise stay put. (May 2026 fix.) */
    getCustomItemRectsAllInGroup(target.data_groupId).forEach(rect => {
        if (rect === target) return;
        if (_groupDragSnapshot.others.has(rect)) return;
        _groupDragSnapshot.others.set(rect, { x: rect.x(), y: rect.y() });
    });
}

/* Apply group drag-follow during a member-direct drag.
 * Skips when the Transformer itself is being dragged (in which case Konva
 * already moves every node in tr.nodes() natively — double-shift would
 * compound the move). The snapshot is normally captured by the dragstart
 * hooks on imageItem/tblWallFlr; the `if (!_groupDragSnapshot)` block here
 * is a fallback for any code path that calls this without a prior dragstart
 * (the resulting snapshot will still be at the pre-mouse-move position
 * because Konva fires dragstart before the first dragmove). */
function followGroupDragFromMember(target) {
    if (!target || !target.data_groupId) return;
    if (tr.isDragging()) { _groupDragSnapshot = null; return; }

    if (!_groupDragSnapshot || _groupDragSnapshot.target !== target) {
        beginGroupDragFollow(target);
        if (!_groupDragSnapshot) return; /* tr.isDragging guard kicked in */
    }

    const dx = target.x() - _groupDragSnapshot.startPos.x;
    const dy = target.y() - _groupDragSnapshot.startPos.y;
    if (dx === 0 && dy === 0) return;
    _groupDragSnapshot.others.forEach((startPos, node) => {
        node.x(startPos.x + dx);
        node.y(startPos.y + dy);
        /* Each moved sibling has its own coverage (#fov~, #audio~,
         * #dispDist~, #speaker~) and label (#label~) that need to track
         * the move — same call the single-item dragmove handler makes for
         * the dragged item itself. Skip the Group rect (data_deviceid='group'
         * isn't in allDeviceTypes, which moveShading's `allDeviceTypes[id].depth`
         * would crash on if a stale shading node ever existed) AND skip
         * CustomItem rects (data_deviceid='customItem' — no coverage either,
         * and they are now snapshotted alongside the Group rect when a Group
         * fully contains a CustomItem; see beginGroupDragFollow). */
        if (node.data_deviceid !== 'group' && node.data_deviceid !== 'customItem') {
            updateShading(node);
        }
    });
    /* No batchDraw() — Konva v8+ auto-redraws on the next animation frame
     * after the .x()/.y() mutations above (Konva.autoDrawEnabled defaults
     * to true). Calling batchDraw() here would just queue a duplicate rAF. */
    /* Keep the Details-panel X/Y in sync with the live drag, same as the
     * `if (tr.nodes().length === 1) updateFormatDetails(...)` call in the
     * single-item branch of imageItem/tblWallFlr dragmove. */
    refreshGroupDetailsFromCanvas();
}

function endGroupDragFollow() {
    _groupDragSnapshot = null;
}

/* ---- CustomItem drag-follow ----
 * VRC CustomItems behave like Groups for drag/move purposes — they are a
 * second, parallel "bundle" concept. See the Group drag-follow helpers
 * above for the design notes (snapshot in dragstart, not dragmove). The
 * CustomItem variant follows the same pattern with one wrinkle: when an
 * item belongs to BOTH a Group and a CustomItem, the Group's drag-follow
 * runs first and shifts every member (including those that also belong to
 * a CustomItem). The CustomItem rect itself is moved separately by the
 * follower below; if the rect is already in tr.nodes() (Transformer drag),
 * Konva handles its movement natively and this follower no-ops. */
let _customItemDragSnapshot = null;

function beginCustomItemDragFollow(target) {
    if (!target || !target.data_customItemId) return;
    if (tr.isDragging()) { _customItemDragSnapshot = null; return; }
    _customItemDragSnapshot = {
        customItemId: target.data_customItemId,
        target:       target,
        startPos:     { x: target.x(), y: target.y() },
        others:       new Map(),
    };
    getCustomItemMemberNodes(target.data_customItemId).forEach(member => {
        if (member === target) return;
        _customItemDragSnapshot.others.set(member, { x: member.x(), y: member.y() });
    });
    if (groupCustomItemRects) {
        const rectNode = groupCustomItemRects.find(n => n.data_customItemId === target.data_customItemId)[0];
        if (rectNode && rectNode !== target) {
            _customItemDragSnapshot.others.set(rectNode, { x: rectNode.x(), y: rectNode.y() });
        }
    }
}

/* Apply customItem drag-follow during a member-direct drag. Same skip
 * rules as Group: no-op when the Transformer is being dragged (members
 * are moved natively via tr.nodes()) and lazy-fallback to a fresh
 * snapshot if dragstart didn't capture one. The Group follower runs
 * before this on items that belong to both bundles, and the
 * CustomItem rect follower below handles the customItem-specific rect
 * tracking. We skip moving sibling items that ALSO belong to the
 * dragged item's Group, because the Group follower already moved them
 * — moving them again here would double-shift. */
function followCustomItemDragFromMember(target) {
    if (!target || !target.data_customItemId) return;
    if (tr.isDragging()) { _customItemDragSnapshot = null; return; }

    if (!_customItemDragSnapshot || _customItemDragSnapshot.target !== target) {
        beginCustomItemDragFollow(target);
        if (!_customItemDragSnapshot) return;
    }

    const dx = target.x() - _customItemDragSnapshot.startPos.x;
    const dy = target.y() - _customItemDragSnapshot.startPos.y;
    if (dx === 0 && dy === 0) return;

    const dragGroupId = target.data_groupId || null;

    _customItemDragSnapshot.others.forEach((startPos, node) => {
        /* Skip sibling items that the Group follower already moved.
         * The Group follower runs first (its `data_groupId` check) and
         * shifts every Group member by the same delta; if we re-shift
         * here, the item drifts ahead of the rest of the Group. The
         * customItem rect itself has no data_groupId set (rects are
         * stored separately) so it always follows. */
        if (dragGroupId && node.data_groupId === dragGroupId && node.data_deviceid !== 'customItem') {
            return;
        }
        node.x(startPos.x + dx);
        node.y(startPos.y + dy);
        if (node.data_deviceid !== 'customItem' && node.data_deviceid !== 'group') {
            updateShading(node);
        }
    });
    /* No batchDraw() — see beginGroupDragFollow / followGroupDragFromMember
     * for the rationale. Konva v8+ auto-redraws on next rAF. */
    refreshCustomItemDetailsFromCanvas();
}

function endCustomItemDragFollow() {
    _customItemDragSnapshot = null;
}

/* ---- Group helper functions ---- */

function getGroupById(groupId) {
    if (!roomObj.groups) return null;
    return roomObj.groups.find(g => g.groupid === groupId) || null;
}

function ensureGroups(obj) {
    const target = obj || roomObj;
    if (!target.groups) target.groups = [];
}

/* Bounding box in layerTransform-local coords for a single group member.
 * Uses Konva's `getClientRect` — the same API the Transformer calls
 * internally — so the purple Group rect hugs items exactly the way the
 * blue Transformer box does, including correct handling of rotation,
 * stroke, image offsets, and the `smallItemsHighlight` outline trick.
 * `skipShadow: true` because shadows aren't part of the visual extent
 * we care about. `skipStroke` is left at its default (false) so stroked
 * items report their full painted bounds. */
function getMemberBoundingRect(node) {
    return node.getClientRect({
        skipShadow: true,
        relativeTo: layerTransform,
    });
}

/* Return all Konva nodes (across all item groups) whose data_groupId matches groupId */
function getGroupMemberNodes(groupId) {
    const members = [];
    allNodeShapeGroups.forEach(kg => {
        kg.getChildren().forEach(node => {
            if (node.data_groupId === groupId) members.push(node);
        });
    });
    return members;
}

/* Recalculate the Group rect's x, y, width, height from current member positions
 * and update both the Konva node and the roomObj.groups entry. */
function updateGroupBounds(groupId) {
    if (!groupGroupRects) return;
    const members = getGroupMemberNodes(groupId);
    if (!members.length) return;

    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    members.forEach(node => {
        const r = getMemberBoundingRect(node);
        if (r.x < minX) minX = r.x;
        if (r.y < minY) minY = r.y;
        if (r.x + r.width  > maxX) maxX = r.x + r.width;
        if (r.y + r.height > maxY) maxY = r.y + r.height;
    });

    /* No padding — match the Transformer's tight blue box exactly. */
    const newX = minX;
    const newY = minY;
    const newW = maxX - minX;
    const newH = maxY - minY;

    /* Update Konva node */
    const groupRectNode = groupGroupRects.find(n => n.data_groupId === groupId)[0];
    if (groupRectNode) {
        groupRectNode.x(newX);
        groupRectNode.y(newY);
        groupRectNode.width(newW);
        groupRectNode.height(newH);
    }

    /* Update roomObj.groups entry (in unit space) */
    const g = getGroupById(groupId);
    if (g) {
        g.x = ((newX - pxOffset) / scale) + activeRoomX;
        g.y = ((newY - pyOffset) / scale) + activeRoomY;
        g.width  = newW / scale;
        g.height = newH / scale;
        const zPositions = members
            .map(n => parseFloat(n.data_zPosition) || 0)
            .filter(z => !isNaN(z));
        if (zPositions.length) g.data_zPosition = Math.min(...zPositions);
    }
}

/* Returns { rectNode, group, groupId } when the current (or supplied) tr.nodes()
 * represents exactly one group's bundle — a single Group rect plus only members
 * of that same group. Returns null otherwise (mixed selection, multiple groups,
 * group plus stranger items, etc.). Used by enableCopyDelBtn() and the right-
 * click menu logic to recognise a "single conceptual item" group selection. */
function getActiveGroupSelection(nodes) {
    nodes = nodes || tr.nodes();
    if (!nodes || !nodes.length) return null;
    const groupRects = nodes.filter(n => n.data_deviceid === 'group');
    if (groupRects.length !== 1) return null;
    const rectNode = groupRects[0];
    const groupId = rectNode.data_groupId;
    if (!groupId) return null;
    /* Every other node must be a member of this same group OR a
     * CustomItem rect that's a fellow traveler (its members are also in
     * this group). expandSelectionForGroups() pulls customItem rects
     * alongside group selections; without this allowance the active-group
     * detection would fail and the panel would fall back to multi-item. */
    const allBelong = nodes.every(n =>
        n === rectNode ||
        n.data_deviceid === 'customItem' ||
        n.data_groupId === groupId
    );
    if (!allBelong) return null;
    const group = getGroupById(groupId);
    if (!group) return null;
    return { rectNode: rectNode, group: group, groupId: groupId };
}

/* Returns the visual centre of a (possibly rotated) Konva.Rect in parent
 * (layerTransform) coords. The rect's origin is its unrotated top-left, so
 * the centre is (w/2, h/2) rotated by the rect's rotation and translated
 * back to (rect.x, rect.y). Used as the rotation pivot when the user
 * changes the Group's Rotation field — members rotate around this point so
 * the group's visual centre stays put. */
function getRotatedRectCenter(rectNode) {
    const r = rectNode.rotation();
    const rad = Math.PI / 180 * r;
    const cosR = Math.cos(rad);
    const sinR = Math.sin(rad);
    const halfW = rectNode.width() / 2;
    const halfH = rectNode.height() / 2;
    return {
        x: rectNode.x() + halfW * cosR - halfH * sinR,
        y: rectNode.y() + halfW * sinR + halfH * cosR,
    };
}

/* Rotate a Konva node around an arbitrary parent-space point by deltaR degrees.
 * Standard rigid-body rotation: rotate the node's origin around (cx, cy) by
 * deltaR AND increment the node's own rotation by deltaR. This works for any
 * node regardless of its offsetX/Y because Konva's rotation pivot is always
 * the node's local (0,0) — moving (0,0) and rotating in lock-step keeps every
 * point of the node rigid with the rotation around (cx, cy). */
function rotateNodeAroundPoint(node, cx, cy, deltaR) {
    if (!deltaR) return;
    const newPos = rotatePointAroundOrigin(node.x(), node.y(), cx, cy, deltaR);
    node.x(newPos.x);
    node.y(newPos.y);
    node.rotation(node.rotation() + deltaR);
}

/* Push the live X / Y / Rotation / Width / Length of the active Group's rect
 * into the matching Details-panel inputs without re-running the heavier
 * populateGroupDetails() (no show/hide work, no dropdown rebuilds). Called
 * during drags and rotations so the form tracks the canvas in real time —
 * mirrors the per-item `if (tr.nodes().length === 1) updateFormatDetails(e)`
 * call inside the imageItem/tblWallFlr dragmove handlers. No-op when the
 * current selection isn't a single Group bundle. */
function refreshGroupDetailsFromCanvas() {
    const sel = getActiveGroupSelection();
    if (!sel) return;
    const r = sel.rectNode;
    const itemX   = document.getElementById('itemX');
    const itemY   = document.getElementById('itemY');
    const itemRot = document.getElementById('itemRotation');
    const itemW   = document.getElementById('itemWidth');
    const itemL   = document.getElementById('itemLength');
    if (itemX)   itemX.value   = round(((r.x() - pxOffset) / scale) + activeRoomX);
    if (itemY)   itemY.value   = round(((r.y() - pyOffset) / scale) + activeRoomY);
    if (itemRot) itemRot.value = round(r.rotation(), -1);
    if (itemW)   itemW.value   = round(r.width()  / scale);
    if (itemL)   itemL.value   = round(r.height() / scale);
}

/* Populate the right-hand Details panel with Group fields when the selection
 * is a single VRC Group. Called from updateFormatDetails() when the active
 * shape is a Group rect. Width/Length are read-only (groups are sized by
 * their members and resize anchors are disabled on the Transformer);
 * X/Y/Z/Rotation/Label/Layer are editable through updateItem() →
 * updateGroupItem(). */
function populateGroupDetails(rectNode) {
    const group = getGroupById(rectNode.data_groupId);
    if (!group) return;

    /* Hide everything that doesn't apply to a Group. The companion non-group
     * branch in updateFormatDetails re-shows itemNameDiv at its top so we
     * don't strand it hidden when the user clicks back to a normal item. */
    const hideIds = [
        'itemNameDiv', 'labelPathId', 'itemTopElevationDiv', 'itemDiagonalTvDiv',
        'itemVheightDiv', 'trapNarrowWidthDiv', 'tblRectRadiusDiv', 'tblRectRadiusRightDiv',
        'itemTiltSlantDiv', 'itemTiltDiv', 'itemSlantDiv', 'isPrimaryDiv',
        'itemOffsetDiv', 'roleDiv', 'mountDiv', 'colorDiv',
    ];
    hideIds.forEach(id => {
        const el = document.getElementById(id);
        if (el) el.style.display = 'none';
    });

    /* Show the divs we use */
    const showIds = [
        'labelFieldDiv', 'itemLayerDiv', 'itemWidthLengthDiv',
        'itemWidthDiv', 'itemLengthDiv', 'itemRotationDiv',
    ];
    showIds.forEach(id => {
        const el = document.getElementById(id);
        if (el) el.style.display = '';
    });

    document.getElementById('itemLabeldiv').textContent = 'Group Name:';
    document.getElementById('labelField').value = group.name || '';

    /* X / Y track the rect's own (top-left) origin, same convention as
     * tables/walls so the value the user sees matches what canvasToJson()
     * stores in roomObj.groups. */
    document.getElementById('itemX').value = round(((rectNode.x() - pxOffset) / scale) + activeRoomX);
    document.getElementById('itemY').value = round(((rectNode.y() - pyOffset) / scale) + activeRoomY);
    document.getElementById('itemZposition').value = (group.data_zPosition != null) ? group.data_zPosition : 0;

    /* Width / Length are display-only — they reflect the bounding box of
     * the group's members and are recomputed by updateGroupBounds() / the
     * Konva Transformer, never typed in directly. */
    document.getElementById('itemWidth').value  = round(rectNode.width()  / scale);
    document.getElementById('itemLength').value = round(rectNode.height() / scale);
    document.getElementById('itemWidth').disabled  = true;
    document.getElementById('itemLength').disabled = true;

    document.getElementById('itemRotation').value = round(rectNode.rotation(), -1);

    document.getElementById('itemId').innerText    = group.groupid;
    document.getElementById('itemType').innerText  = 'Group';
    document.getElementById('itemGroup').innerText = '';

    populateLayerDropdown('drpItemLayer', group.data_layerId || '0');
}

/* Apply a group-level edit from the Details panel: X/Y/Z deltas translate
 * every member (and the rect) by the same offset; a rotation delta rotates
 * every member around the Group rect's current visual centre so the group's
 * apparent centre stays put. Label and layer changes cascade to all members.
 * Coverage nodes (FOV, audio, etc.) are re-aligned via updateShading()
 * after the moves. */
function updateGroupItem(group) {
    if (!group || !groupGroupRects) return;
    const rectNode = groupGroupRects.find(n => n.data_groupId === group.groupid)[0];
    if (!rectNode) return;

    const newName = (DOMPurify.sanitize(document.getElementById('labelField').value) || '').trim() || group.name;
    const newX = Number(document.getElementById('itemX').value) || 0;
    const newY = Number(document.getElementById('itemY').value) || 0;
    /* Z field: empty / null / non-numeric all collapse to 0, matching the
     * "treat missing data_zPosition as 0" rule applied to members below. */
    const newZ = Number(document.getElementById('itemZposition').value) || 0;
    const newRot = normalizeDegree(Number(document.getElementById('itemRotation').value) || 0);
    const newLayerId = (document.getElementById('drpItemLayer') && document.getElementById('drpItemLayer').value) || '0';

    /* Compute deltas in the same units the form uses */
    const currentX_user = ((rectNode.x() - pxOffset) / scale) + activeRoomX;
    const currentY_user = ((rectNode.y() - pyOffset) / scale) + activeRoomY;
    /* group.data_zPosition is the group's current baseline (the lowest
     * member z at create time, kept in sync by every updateGroupItem
     * call). Missing / NaN -> 0. */
    const currentZ      = Number(group.data_zPosition) || 0;
    const currentRot    = rectNode.rotation();

    const deltaX_px = (newX - currentX_user) * scale;
    const deltaY_px = (newY - currentY_user) * scale;
    const deltaZ    = newZ - currentZ;
    const deltaR    = newRot - currentRot;

    const members = getGroupMemberNodes(group.groupid);
    /* CustomItem rects whose every member belongs to this Group ride along
     * with the Group during translate / rotate (same rule the drag-follow
     * uses — see beginGroupDragFollow for the rationale). Without this, a
     * Details-panel X / Y / Rotation edit on a Group would leave any
     * fully-contained CustomItem rect floating where it was. */
    const customItemRects = getCustomItemRectsAllInGroup(group.groupid);

    /* 1) Translate first so the rotation pivot we compute next is the
     *    visual centre at the new location. */
    if (deltaX_px !== 0 || deltaY_px !== 0) {
        members.forEach(m => { m.x(m.x() + deltaX_px); m.y(m.y() + deltaY_px); });
        rectNode.x(rectNode.x() + deltaX_px);
        rectNode.y(rectNode.y() + deltaY_px);
        customItemRects.forEach(r => { r.x(r.x() + deltaX_px); r.y(r.y() + deltaY_px); });
    }

    /* 2) Rigid rotation around the (post-translation) rect centre. */
    if (deltaR !== 0) {
        const centre = getRotatedRectCenter(rectNode);
        members.forEach(m => rotateNodeAroundPoint(m, centre.x, centre.y, deltaR));
        rotateNodeAroundPoint(rectNode, centre.x, centre.y, deltaR);
        customItemRects.forEach(r => rotateNodeAroundPoint(r, centre.x, centre.y, deltaR));
    }

    /* 3) Z elevation: deltaZ adds to every member's data_zPosition.
     *    A member with no existing data_zPosition (or NaN/non-numeric) is
     *    treated as 0, so the new value lands at exactly deltaZ. The group
     *    object then holds the new baseline (which equals newZ since every
     *    member was shifted by the same amount, preserving the relative
     *    stack). The early-return on `deltaZ === 0` avoids polluting nodes
     *    that previously had no data_zPosition with an explicit `0`. */
    if (deltaZ !== 0) {
        members.forEach(m => {
            const existingZ = Number(m.data_zPosition) || 0;
            m.data_zPosition = existingZ + deltaZ;
            /* Mirror to roomObj.items immediately. canvasToJson() at the end
             * of this function rebuilds roomObj from canvas state, but only
             * writes data_zPosition when it's `in` the node — and a member
             * that was never assigned a z before has no own property, so a
             * stale write order (or any future reorder) could miss it. The
             * direct mirror keeps roomObj.items in sync regardless. */
            if (roomObj && roomObj.items) {
                for (const cat in roomObj.items) {
                    if (!Array.isArray(roomObj.items[cat])) continue;
                    const entry = roomObj.items[cat].find(it => it.id === m.id());
                    if (entry) { entry.data_zPosition = m.data_zPosition; break; }
                }
            }
        });
    }
    group.data_zPosition = newZ;
    rectNode.data_zPosition = newZ;

    /* 4) Group name */
    group.name = newName;
    rectNode.data_labelField = newName;

    /* 5) Layer cascade — share-a-layer invariant matches createGroup(). */
    if (newLayerId !== (group.data_layerId || '0')) {
        group.data_layerId = newLayerId;
        rectNode.data_layerId = newLayerId;
        applyLayerStateToNode(rectNode, newLayerId);
        members.forEach(m => {
            m.data_layerId = newLayerId;
            applyLayerStateToNode(m, newLayerId);
        });
        renderLayersList();
    }

    /* 6) Re-align FOV / audio / display-distance / labels for moved members. */
    members.forEach(m => updateShading(m));

    /* No batchDraw() — Konva v8+ auto-redraws on next rAF after the
     * x/y/rotation mutations above (Konva.autoDrawEnabled === true). */
    canvasToJson();

    /* Match the existing single-item updateItem button-debounce. */
    const btn = document.getElementById("btnUpdateItemId");
    if (btn) {
        btn.disabled = true;
        setTimeout(() => { btn.disabled = false; }, 700);
    }
}

/* ---- CustomItem helper functions ----
 *
 * CustomItems are a parallel bundling concept to Groups: a CustomItem
 * groups items so they move/rotate as a unit (same UX as a Group), but
 * with a *weaker* selection precedence. When an item belongs to both a
 * Group and a CustomItem, clicking it selects the Group; the CustomItem
 * rect rides along but doesn't capture the Details panel.
 *
 * The data shape mirrors roomObj.groups exactly — see CLAUDE.md "VRC
 * Group System" for the conventions. CustomItem rects render in
 * `groupCustomItemRects` (a Konva.Group added to layerTransform AFTER
 * groupGroupRects so they paint on top of group rects but still behind
 * items). Visual difference: light green fill / green stroke, vs the
 * group's light blue / blue stroke.
 */

function getCustomItemById(customItemId) {
    if (!roomObj.customItems) return null;
    return roomObj.customItems.find(c => c.customitemid === customItemId) || null;
}

function ensureCustomItems(obj) {
    const target = obj || roomObj;
    if (!target.customItems) target.customItems = [];
}

/* Defensive backfill — assign customItemBaseId to any customItem that
 * lacks one (older room JSON, URL-decoded customItems, WD imports
 * without baseId, undo snapshots from pre-baseId releases). Idempotent:
 * customItems that already have a customItemBaseId are left alone, so
 * calling this on every save is cheap. The baseId is the family /
 * template id used as the IndexedDB Custom Item Library primary key
 * and for "same template" detection on import — see createCustomItem()
 * for the full rationale. Returns the count of items that were
 * backfilled (useful for logging). */
function ensureCustomItemBaseIds(obj) {
    const target = obj || roomObj;
    if (!target || !Array.isArray(target.customItems)) return 0;
    let assigned = 0;
    target.customItems.forEach(c => {
        if (!c) return;
        if (!c.customItemBaseId) {
            c.customItemBaseId = createUuid();
            assigned++;
        }
    });
    return assigned;
}

/* Populate the customItemLibraryIds Set from IndexedDB. Called once on
 * page load (from onLoad). Safe to call again if a future workflow needs
 * to resync after an external IDB mutation (none today). Resolves on
 * completion; never rejects — IDB unavailability is logged and the cache
 * stays empty (every "in library?" check returns false, which the UI
 * gracefully handles by hiding the "Remove from Library" option). */
function hydrateCustomItemLibraryIds() {
    if (!window.idbStore || typeof window.idbStore.customItemGetAllIds !== 'function') {
        return Promise.resolve();
    }
    return window.idbStore.customItemGetAllIds()
        .then(ids => {
            customItemLibraryIds = new Set(ids || []);
            console.info('[customItemLibrary] hydrated', customItemLibraryIds.size, 'template id(s) from IDB');
            /* Initial enable/disable for the Settings → Export Custom
             * Items button. Subsequent state changes (Add to Library,
             * Unjoin, tile delete, import) are picked up by the
             * mark/unmark hooks. */
            if (typeof updateExportCustomItemsButtonState === 'function') {
                updateExportCustomItemsButtonState();
            }
        })
        .catch(e => {
            console.warn('[customItemLibrary] hydrate failed:', e && e.message);
        });
}

/* One-shot boot migration: re-render menuImages for any library record
 * whose stored renderer version is older than CUSTOM_ITEM_MENU_IMAGE_VERSION.
 * Runs after hydrateCustomItemLibraryIds(). No-ops on subsequent boots
 * (every refreshed record is stamped with the current version), so the
 * IDB write cost is paid exactly once per renderer-version bump.
 *
 * Per-record renders run serially (await each createCustomItemMenuImage
 * before the next) so we don't slam the main thread with N parallel
 * temp-stages on slow devices. With MAX_CUSTOM_ITEMS=200 the worst case
 * is bounded and still fast — empirically ~10-50ms per record. */
function refreshStaleCustomItemMenuImages() {
    if (!window.idbStore ||
        typeof window.idbStore.customItemGetAll !== 'function' ||
        typeof window.idbStore.customItemPut !== 'function') {
        return Promise.resolve();
    }
    return window.idbStore.customItemGetAll()
        .then(function (records) {
            if (!Array.isArray(records) || !records.length) return;
            const stale = records.filter(r =>
                r && (Number(r.menuImageVersion) || 0) < CUSTOM_ITEM_MENU_IMAGE_VERSION
            );
            if (!stale.length) return;
            console.info('[customItemLibrary] refreshing menuImage for',
                stale.length, 'stale record(s) (renderer v' + CUSTOM_ITEM_MENU_IMAGE_VERSION + ')');
            /* Reduce-chain so renders are serial. Errors on any single
             * record are swallowed (and the record stays at its old
             * version, so the next boot will retry) — never block boot. */
            return stale.reduce(function (chain, rec) {
                return chain.then(function () {
                    return createCustomItemMenuImage(rec)
                        .then(function (dataUrl) {
                            rec.menuImage = dataUrl || rec.menuImage || '';
                            rec.menuImageVersion = CUSTOM_ITEM_MENU_IMAGE_VERSION;
                            return window.idbStore.customItemPut(rec);
                        })
                        .catch(function (e) {
                            console.warn('[customItemLibrary] refresh failed for',
                                rec && rec.customItemBaseId, e && e.message);
                        });
                });
            }, Promise.resolve());
        })
        .catch(function (e) {
            console.warn('[customItemLibrary] refreshStaleCustomItemMenuImages failed:', e && e.message);
        });
}

/* Synchronous predicate — UI hot path. Falsy / unknown baseIds always
 * return false so callers can pass through possibly-missing values. */
function isCustomItemInLibrary(customItemBaseId) {
    if (!customItemBaseId) return false;
    return customItemLibraryIds.has(customItemBaseId);
}

/* Record that a baseId now exists in IDB. Callers MUST invoke this
 * immediately after a successful idbStore.customItemPut() so the menu /
 * Quick Add UI reflects the new library state on the next render —
 * crucial because the IDB write is async but the menu re-renders
 * synchronously on the next pointer event. */
function markCustomItemInLibrary(customItemBaseId) {
    if (!customItemBaseId) return;
    const before = customItemLibraryIds.size;
    customItemLibraryIds.add(customItemBaseId);
    /* Only refresh the Settings export-button state when the membership
     * count actually changed (re-mark of an existing baseId is a no-op
     * on the Set, but we'd otherwise still pay a DOM-reflow cost on
     * every save). */
    if (customItemLibraryIds.size !== before &&
        typeof updateExportCustomItemsButtonState === 'function') {
        updateExportCustomItemsButtonState();
    }
}

/* Inverse of mark — invoked after idbStore.customItemDelete() succeeds. */
function unmarkCustomItemInLibrary(customItemBaseId) {
    if (!customItemBaseId) return;
    const before = customItemLibraryIds.size;
    customItemLibraryIds.delete(customItemBaseId);
    if (customItemLibraryIds.size !== before &&
        typeof updateExportCustomItemsButtonState === 'function') {
        updateExportCustomItemsButtonState();
    }
}

/* Compute a single customItem member's geometry in the customItem's
 * normalized local frame — i.e. with the customItem's upper-left at
 * (0, 0) and the customItem's rotation removed. Shared by:
 *
 *   - buildCustomItemExportRecord() — writes the part's normalized x/y/
 *     rotation into the .vrcCustomItems JSON, so an importer dropping
 *     the template at any (x, y) with any rotation can place each part
 *     correctly with a single rigid-body transform.
 *   - createCustomItemMenuImage() — renders the parts into a 100×100
 *     temporary Konva stage; needs the same normalized rect so the
 *     thumbnail shows the template in its "natural" pose.
 *
 * Inputs:
 *   item        - a roomObj item entry (plain object). Always uses the
 *                 persisted roomObj data so the caller must run
 *                 canvasToJson() first if reading from a freshly-edited
 *                 canvas. roomObj item x/y are world coords in
 *                 roomObj.unit (meters or feet) with activeRoomX/Y baked
 *                 in; that's the same frame customItem.x/y uses, so the
 *                 subtraction below cancels both offsets cleanly.
 *   customItem  - the parent roomObj.customItems[] entry providing x, y,
 *                 rotation (and width/height for sanity).
 *
 * Returns:
 *   {
 *     data_deviceid: string,
 *     localX, localY:        number  // unit space (matches roomObj.unit),
 *                                    //   customItem-local, upper-left = 0,0
 *     width, height:         number  // intrinsic part size in roomObj.unit;
 *                                    //   resolved from the device library
 *                                    //   when the item itself lacks them
 *     localRotation:         number  // degrees, normalized to (-180, 180]
 *   }
 *   or null if inputs are invalid. Unit conversion to meters (for the
 *   JSON export) is left to the caller — keeping this helper unit-agnostic
 *   means menu-image rendering (which renders in roomObj.unit directly)
 *   doesn't pay a double-conversion cost.
 *
 * Math: customItem.x/y is the rect's upper-left in world coords AND the
 * rect's rotation pivot (Konva default offsetX/Y = 0). For a part at
 * world (px, py) with rotation φ, the normalized local position is the
 * world-delta rotated by -θ where θ = customItem.rotation:
 *
 *     localX =  cos(θ) * dx + sin(θ) * dy
 *     localY = -sin(θ) * dx + cos(θ) * dy
 *     localRotation = φ - θ
 *
 * with dx = px - customItem.x, dy = py - customItem.y.
 */
function getPartRenderRect(item, customItem) {
    if (!item || !customItem) return null;
    if (!item.data_deviceid) return null;

    /* Resolve width/height — most items carry explicit width/height in
     * roomObj.unit, but fixed-size devices (cameras, mics, room bars)
     * store nothing and pull from the device library at render time.
     * Device library uses mm: width = horizontal, depth = vertical (on
     * the floor plan). `.height` on the device library is the 3D
     * vertical extent (data_vHeight) — unrelated to floor footprint. */
    let w = Number(item.width);
    let h = Number(item.height);
    if (!w || !h) {
        const dt = allDeviceTypes && allDeviceTypes[item.data_deviceid];
        if (dt) {
            if (!w && typeof dt.width === 'number') w = dt.width / 1000;
            if (!h && typeof dt.depth === 'number') h = dt.depth / 1000;
        }
        /* Feet rooms need the mm→meters conversion above to be re-scaled
         * to feet for parity with item.x/item.y storage convention. */
        if (roomObj && roomObj.unit === 'feet') {
            if (!Number(item.width) && w) w = w * 3.28084;
            if (!Number(item.height) && h) h = h * 3.28084;
        }
    }
    w = w || 0;
    h = h || 0;

    const partX = Number(item.x) || 0;
    const partY = Number(item.y) || 0;
    const partRotation = Number(item.rotation) || 0;
    const ciX = Number(customItem.x) || 0;
    const ciY = Number(customItem.y) || 0;
    const ciRotation = Number(customItem.rotation) || 0;

    const dx = partX - ciX;
    const dy = partY - ciY;

    const theta = ciRotation * Math.PI / 180;
    const cosT = Math.cos(theta);
    const sinT = Math.sin(theta);
    const localX = cosT * dx + sinT * dy;
    const localY = -sinT * dx + cosT * dy;

    let localRotation = partRotation - ciRotation;
    /* Wrap into (-180, 180] — keeps the export numbers human-readable
     * and stable across multiple round-trips (otherwise the delta could
     * drift by ±360 on every export/import cycle). */
    while (localRotation > 180) localRotation -= 360;
    while (localRotation <= -180) localRotation += 360;

    return {
        data_deviceid: item.data_deviceid,
        localX: localX,
        localY: localY,
        width: w,
        height: h,
        localRotation: localRotation,
    };
}

/* Look up a roomObj item entry by its uuid across every category in
 * roomObj.items. Linear scan — every category checked because the
 * customItem.customItemMembers array is uuids without category hints.
 * Returns null if not found (member was deleted out from under the
 * customItem, which the cleanup pass in updateCustomItemBounds will
 * eventually reconcile). */
function findRoomItemByUuid(uuid) {
    if (!uuid || !roomObj || !roomObj.items) return null;
    for (const category in roomObj.items) {
        if (!Array.isArray(roomObj.items[category])) continue;
        const found = roomObj.items[category].find(i => i && i.id === uuid);
        if (found) return found;
    }
    return null;
}

/* Whitelist of per-part `data_*` fields that round-trip through the
 * .vrcCustomItems export / IDB record / .vrcCustomItems import path.
 * Fields NOT in this list are intentionally dropped:
 *
 *   id, data_layerId       — customItem owns the layer; parts inherit.
 *   data_groupId           — createCustomItem dissolves Group membership
 *                            before assembling members, so this is never
 *                            present on customItem members.
 *   data_customItemId,
 *   data_customItemBaseId  — implicit from being inside a customItem.
 *   x, y, rotation         — replaced by the normalized localX/localY/
 *                            localRotation values from getPartRenderRect.
 *   width, height          — emitted separately (always, even if absent
 *                            on the source) so the importer never needs
 *                            to fall back to the device library to know
 *                            a part's footprint.
 *
 * Numeric fields stored in roomObj.unit (meters or feet) are converted
 * to meters on export — see CUSTOM_ITEM_UNIT_SCALED_PART_FIELDS. */
const CUSTOM_ITEM_PART_VERBATIM_FIELDS = [
    'data_color',
    'data_labelField',
    'data_role',
    'data_mount',
    'data_tilt',
    'data_slant',
    'data_diagonalInches',
    'data_fovHidden',
    'data_audioHidden',
];

/* Per-part fields whose stored value is in roomObj.unit (meters / feet)
 * and therefore must be scaled to meters for the export JSON. */
const CUSTOM_ITEM_UNIT_SCALED_PART_FIELDS = [
    'data_zPosition',
    'data_vHeight',
    'data_trapNarrowWidth',
    'tblRectRadius',
    'tblRectRadiusRight',
];

/* Build the serializable export record for a single customItem. The
 * returned object matches the .vrcCustomItems file format exactly — same
 * shape is stored verbatim in IDB (so a saved export can be put without
 * reshaping). All measurements are emitted in METERS regardless of the
 * room's active unit; the importer always reads meters too, so a
 * customItem exported from a feet room loads correctly into a meters
 * room (and vice versa).
 *
 * menuImage is intentionally left empty here — createCustomItemMenuImage
 * resolves asynchronously (Image.onload across every part) so the
 * export pipeline merges the menuImage onto the returned record after
 * the image promise settles.
 *
 * Returns null when:
 *   - customItem is missing or lacks customItemBaseId
 *   - customItem has no members (would produce an empty parts array,
 *     which the importer rejects)
 *
 * Side-effect-free: never mutates roomObj or the customItem. Safe to
 * call from any UI flow including the menu-open path.
 */
function buildCustomItemExportRecord(customItem) {
    if (!customItem || !customItem.customItemBaseId) return null;
    if (!Array.isArray(customItem.customItemMembers) || !customItem.customItemMembers.length) return null;

    const unitToMeters = (roomObj && roomObj.unit === 'feet') ? (1 / 3.28084) : 1;

    const parts = [];
    customItem.customItemMembers.forEach(uuid => {
        const item = findRoomItemByUuid(uuid);
        if (!item) return;
        const rect = getPartRenderRect(item, customItem);
        if (!rect) return;

        const part = {
            data_deviceid: rect.data_deviceid,
            x: rect.localX * unitToMeters,
            y: rect.localY * unitToMeters,
            width: rect.width * unitToMeters,
            height: rect.height * unitToMeters,
            rotation: rect.localRotation,
        };

        CUSTOM_ITEM_PART_VERBATIM_FIELDS.forEach(field => {
            if (item[field] !== undefined && item[field] !== null) {
                /* Object/array fields (data_color, data_labelField) — deep
                 * clone so later edits to the canvas instance can't mutate
                 * the IDB record through a shared reference. JSON
                 * round-trip is sufficient for the value shapes we use. */
                if (typeof item[field] === 'object') {
                    try { part[field] = JSON.parse(JSON.stringify(item[field])); }
                    catch (e) { part[field] = item[field]; }
                } else {
                    part[field] = item[field];
                }
            }
        });

        CUSTOM_ITEM_UNIT_SCALED_PART_FIELDS.forEach(field => {
            const v = item[field];
            if (typeof v === 'number') part[field] = v * unitToMeters;
        });

        /* cornerRadius is either a number or a 4-element array (Konva
         * convention for per-corner radii). Scale either shape. */
        if (typeof item.cornerRadius === 'number') {
            part.cornerRadius = item.cornerRadius * unitToMeters;
        } else if (Array.isArray(item.cornerRadius)) {
            part.cornerRadius = item.cornerRadius.map(v => (typeof v === 'number' ? v * unitToMeters : v));
        }

        /* `points` is a flat [x0, y0, x1, y1, ...] array used by lines
         * and polyRoom — uniformly scale every entry, including the
         * implicit y values, since unit conversion is isotropic. */
        if (Array.isArray(item.points)) {
            part.points = item.points.map(v => (typeof v === 'number' ? v * unitToMeters : v));
        }

        parts.push(part);
    });

    if (!parts.length) return null;

    return {
        customItemBaseId: customItem.customItemBaseId,
        data_labelField: String(customItem.name || ''),
        width: (Number(customItem.width) || 0) * unitToMeters,
        height: (Number(customItem.height) || 0) * unitToMeters,
        customItemParts: parts,
        menuImage: '', /* populated by createCustomItemMenuImage() */
    };
}

/* Render a 100×100 JPEG thumbnail of a customItem template — used as the
 * Quick Add palette tile and saved alongside the IDB library record.
 * Parts are fit into an INNER × INNER (90×90) box centered in the 100×100
 * frame so there's a uniform padding around every thumbnail. The whole
 * template renders in its NORMALIZED pose (rotation = 0, origin = upper-
 * left) — that's the pose the import path drops a fresh instance in too,
 * so the thumbnail and the inserted item always look the same.
 *
 * Mirrors the temp-stage / toDataURL pattern from updateSingleHighlightImage
 * but with two important differences:
 *
 *   1. NO orange highlight ring — the menu thumbnail is a clean
 *      representation, not a hover indicator. createHighlightRect()
 *      is intentionally not called here.
 *   2. Multi-image safe — every part with a topImage triggers an async
 *      Image() load; we Promise.all() the lot before toDataURL() so the
 *      final JPEG always contains all parts. (The original
 *      createHighlightImage has a latent race condition for the
 *      single-image case — a multi-image clone would amplify it.)
 *
 * Returns a Promise resolving to a data:image/jpeg;base64,... string,
 * or '' (empty string) if rendering failed. Caller proceeds with an
 * empty menuImage on failure — the library record is still useful for
 * import even without a thumbnail, and the palette tile can fall back
 * to a generic placeholder. */
function createCustomItemMenuImage(record) {
    const FULL = 100;          /* total thumbnail size, px */
    const INNER = 90;          /* drawable region inside the padding, px */

    if (!record || !Array.isArray(record.customItemParts) || !record.customItemParts.length) {
        return Promise.resolve('');
    }

    /* Per-part anchor convention. updateRoomObjFromTrNode() stores
     * roomObj.items[].x/y as the UPPER-LEFT for tables / stageFloors /
     * boxes / rooms (Konva's default-pivot devices), and as the CENTER
     * for every other parentGroup (the offsetX=w/2 / offsetY=h/2 idiom).
     * pathShape is in the 'tables' parentGroup BUT its (x, y) is the
     * Konva.Path's local origin (where path-(0,0) lands) — not a UL.
     *
     * getPartRenderRect() preserves whichever convention the source item
     * used into the exported `part.x` / `part.y` — it never normalises.
     * So this function MUST branch per-device when both placing the
     * Konva node (anchor offsets) AND when rendering it (rect vs path,
     * which style to apply). */
    function partAnchorIsUL(part) {
        const dt = (typeof allDeviceTypes !== 'undefined' && allDeviceTypes)
            ? allDeviceTypes[part.data_deviceid] : null;
        if (!dt) return false;
        const pg = dt.parentGroup;
        return pg === 'tables' || pg === 'stageFloors' || pg === 'boxes' || pg === 'rooms';
    }

    /* Temporary off-DOM container for the Konva stage. Unique id per call
     * so concurrent renders (rare but possible: import of N customItems)
     * never collide. Cleaned up on resolution OR rejection. */
    const divContainerId = 'containerCustomItemMenuImageCreate-' + createUuid();
    const existing = document.getElementById(divContainerId);
    if (existing) existing.remove();
    const container = document.createElement('div');
    container.id = divContainerId;
    container.style.display = 'none';
    document.body.appendChild(container);

    let stage, layer;
    try {
        stage = new Konva.Stage({ container: divContainerId, width: FULL, height: FULL });
        layer = new Konva.Layer();
        stage.add(layer);
    } catch (e) {
        console.warn('[customItemLibrary] menuImage stage create failed:', e && e.message);
        if (container.parentNode) container.parentNode.removeChild(container);
        return Promise.resolve('');
    }

    /* pathShape stores its presentation (path data, scale, fill, opacity)
     * inside data_labelField as a JSON object. The canvas renderer at
     * insertDevice.id === 'pathShape' applies the same parsing — we
     * mirror it here so the thumbnail matches what the user sees. Regex
     * (not JSON.parse) is used because the labelField historically also
     * carries free-text comments alongside the JSON object. */
    function parsePathShapeLabel(labelField) {
        const out = { path: 'M-0.5-0.5 h1.2 l0.1 1 l-0.5 -0.4 L-0.5 0.5z',
                      scaleX: 1, scaleY: 1, fill: '#D3D3D3', opacity: 0.4 };
        if (typeof labelField !== 'string') return out;
        const pm = labelField.match(/"path"\s*:\s*"\s*([Mm][^"]*)"/);
        if (pm && pm[1]) out.path = pm[1];
        const sm = labelField.match(/"scale"\s*:\s*\[\s*([\-0-9.]+)\s*,\s*[\-0-9.]+\s*,\s*([\-0-9.]+)\s*\]/);
        if (sm) { out.scaleX = Number(sm[1]) || 1; out.scaleY = Number(sm[2]) || 1; }
        const cm = labelField.match(/"color"\s*:\s*"([^"]+)"/);
        if (cm && cm[1]) out.fill = cm[1];
        const om = labelField.match(/"opacity"\s*:\s*"?([\d.]+)"?/);
        if (om) out.opacity = parseFloat(om[1]);
        return out;
    }

    /* Build the Konva node for one part at METER scale (i.e. no
     * thumbnail-fit scaling yet). Position is in part-frame METERS, so
     * we can read layer.getClientRect() afterwards to compute the union
     * bbox in the same units. The fit-to-INNER scale + center
     * translation is then applied to the whole LAYER below, which keeps
     * per-part math simple and unaffected by stacking order or
     * rotation interactions. Resolves once the node is fully rendered:
     * for Konva.Image that means the underlying Image() has loaded (so
     * toDataURL captures pixels, not an empty bitmap); for Rect/Path
     * it's synchronous so resolves immediately. */
    function addPartNodeAtMeterScale(part) {
        return new Promise(function (resolveOne) {
            const dt = (typeof allDeviceTypes !== 'undefined' && allDeviceTypes)
                ? allDeviceTypes[part.data_deviceid] : null;
            const cx = Number(part.x) || 0;
            const cy = Number(part.y) || 0;
            const rotation = Number(part.rotation) || 0;
            const w = Number(part.width)  || 0;
            const h = Number(part.height) || 0;

            /* pathShape — Konva.Path. (x, y) is where path-(0,0) lands;
             * rotation pivots around that point (Konva default offset).
             * Scale comes from the labelField JSON's "scale" array.
             *
             * strokeScaleEnabled: false keeps the stroke at a fixed
             * pixel width regardless of how aggressively layer.scale()
             * inflates the geometry — without it a small customItem
             * (scaleFactor ~200) would render a 2px-meter stroke as
             * a 400px slab. */
            if (part.data_deviceid === 'pathShape') {
                const lf = parsePathShapeLabel(part.data_labelField);
                layer.add(new Konva.Path({
                    x: cx, y: cy,
                    data: lf.path,
                    fill: lf.fill,
                    stroke: (dt && dt.stroke) || 'black',
                    strokeWidth: 1,
                    strokeScaleEnabled: false,
                    opacity: (typeof lf.opacity === 'number' ? lf.opacity : 0.4),
                    scale: { x: lf.scaleX, y: lf.scaleY },
                    rotation: rotation,
                    /* getClientRect needs the path bbox to participate
                     * in the layer-wide measure. Konva.Path computes it
                     * synchronously from the parsed `data`. */
                }));
                resolveOne();
                return;
            }

            const isUl = partAnchorIsUL(part);
            /* Style mapping. We faithfully replicate the canvas
             * insertItem() branch per device-id so the thumbnail
             * matches what the user dragged onto the canvas:
             *
             *   - box / carpet / stageFloor: fill #FFFFFF99 (canvas
             *     hard-codes this), dashed black stroke from the device
             *     library. data_labelField "color" is METADATA on these
             *     devices and intentionally NOT applied as fill.
             *   - other UL-anchor rects (tables/rooms): use device
             *     stroke + a light grey fill.
             *   - center-anchor + topImage: Konva.Image (async load).
             *   - center-anchor without topImage: device fill if known
             *     else a neutral grey. */
            let nodeAttrs = {
                x: cx, y: cy,
                width: w, height: h,
                rotation: rotation,
                offsetX: isUl ? 0 : w / 2,
                offsetY: isUl ? 0 : h / 2,
            };

            if (part.data_deviceid === 'box' ||
                part.data_deviceid === 'carpet' ||
                part.data_deviceid === 'stageFloor') {
                nodeAttrs.fill = '#FFFFFF99';
                nodeAttrs.stroke = (dt && dt.stroke) || 'black';
                nodeAttrs.strokeWidth = 1;
                nodeAttrs.strokeScaleEnabled = false; /* see pathShape */
                if (dt && Array.isArray(dt.dash)) {
                    /* Pass the device's dash pattern through verbatim.
                     * With strokeScaleEnabled=false the dash values are
                     * interpreted in PIXELS at the visible canvas
                     * resolution, so the on/off pattern looks the same
                     * regardless of how big the customItem is (and
                     * matches the canvas appearance more closely). */
                    nodeAttrs.dash = dt.dash.slice();
                }
                if (typeof part.cornerRadius === 'number') {
                    nodeAttrs.cornerRadius = part.cornerRadius;
                } else if (Array.isArray(part.cornerRadius)) {
                    nodeAttrs.cornerRadius = part.cornerRadius;
                }
                layer.add(new Konva.Rect(nodeAttrs));
                resolveOne();
                return;
            }

            if (dt && dt.topImage) {
                /* Konva.Image — create FIRST so it participates in
                 * layer.getClientRect() (which uses width/height, not
                 * the loaded image pixels). The image bitmap attaches
                 * later inside onload, and we trigger a redraw then. */
                const imageNode = new Konva.Image(Object.assign({ image: null }, nodeAttrs));
                layer.add(imageNode);
                const imgObj = new Image();
                imgObj.onload = function () {
                    imageNode.image(imgObj);
                    layer.batchDraw();
                    resolveOne();
                };
                imgObj.onerror = function () {
                    /* Asset missing — leave as an empty rect outline so
                     * the thumbnail still completes and the user can
                     * tell something is there. */
                    imageNode.stroke('#888888');
                    imageNode.strokeWidth(1);
                    imageNode.strokeScaleEnabled(false);
                    imageNode.fill('#dddddd');
                    layer.batchDraw();
                    resolveOne();
                };
                imgObj.src = './assets/images/' + dt.topImage;
                return;
            }

            /* Final fallback: rect with a best-effort fill. Centre-
             * anchor devices without topImage are rare (e.g. some
             * generic placeholders) — render with a light grey so
             * they're visible. */
            nodeAttrs.fill = '#cccccc';
            nodeAttrs.stroke = (dt && dt.stroke) || '#666666';
            nodeAttrs.strokeWidth = 1;
            nodeAttrs.strokeScaleEnabled = false;
            layer.add(new Konva.Rect(nodeAttrs));
            resolveOne();
        });
    }

    /* Sort parts to match drawRoom()'s z-stacking before rendering.
     * The canvas keeps every item type in a dedicated Konva.Group, and
     * `allNodeShapeGroups` defines their bottom-to-top order on the
     * stage:
     *
     *   rooms → boxes → touchPanels → speakers → displays →
     *   stageFloors → tables → chairs → microphones → videoDevices
     *
     * (so a videoDevice always paints on top of a stageFloor or display
     * it sits on, etc.). Konva.Layer renders children in addition order,
     * so to reproduce that stack we add bottom-to-top per parentGroup,
     * preserving member-insertion order within each group as a tie-
     * breaker. Reading the order from `allNodeShapeGroups` (rather than
     * hard-coding here) keeps this in lockstep with any future canvas
     * reordering — drawRoom() is the source of truth. Unknown
     * parentGroups (defensive: legacy device entries) sort to the end so
     * they paint on top and remain visible rather than getting hidden
     * under a videoDevice's topImage. */
    const groupZOrder = (typeof allNodeShapeGroups !== 'undefined' && Array.isArray(allNodeShapeGroups))
        ? allNodeShapeGroups.map(g => g.name())
        : [];
    function partZIndex(part) {
        const dt = (typeof allDeviceTypes !== 'undefined' && allDeviceTypes)
            ? allDeviceTypes[part.data_deviceid] : null;
        if (!dt || !dt.parentGroup) return groupZOrder.length;
        const idx = groupZOrder.indexOf(dt.parentGroup);
        return idx >= 0 ? idx : groupZOrder.length;
    }
    const orderedParts = record.customItemParts
        .map((part, originalIdx) => ({ part: part, idx: originalIdx, z: partZIndex(part) }))
        .sort((a, b) => (a.z - b.z) || (a.idx - b.idx))
        .map(entry => entry.part);

    /* Pass 1: synchronously create every node at meter scale. Image
     * loads continue in the background but the nodes' width/height
     * (and Path's `data`) are set NOW, so layer.getClientRect() returns
     * the correct bbox even before images finish loading. */
    const partPromises = orderedParts.map(addPartNodeAtMeterScale);

    /* Pass 2: measure layer bbox in meters and apply a layer-wide fit-
     * and-center transform. We re-measure each call (rather than
     * accumulating manually) so any future device-type additions
     * automatically participate without bbox-math changes.
     *
     * skipStroke: true so the placeholder 1-meter strokeWidth we use
     * to anchor `strokeScaleEnabled: false` doesn't poison the bbox —
     * Konva's getClientRect adds halfStrokeWidth on each side by
     * default. The visible stroke at thumbnail render time is small
     * enough (1 px fixed) that the unstroked geometry is what we
     * want fit into INNER × INNER. */
    let bbox = layer.getClientRect({ skipTransform: false, skipStroke: true });
    if (!bbox || !isFinite(bbox.width) || !isFinite(bbox.height) ||
        bbox.width <= 0 || bbox.height <= 0) {
        /* Defensive fallback — should never trigger if any part has
         * non-zero geometry. Use the customItem's own bbox so we still
         * produce a valid scale. */
        bbox = { x: 0, y: 0,
                 width: Number(record.width)  || 1,
                 height: Number(record.height) || 1 };
    }
    const scaleFactor = INNER / Math.max(bbox.width, bbox.height);
    const drawW = bbox.width  * scaleFactor;
    const drawH = bbox.height * scaleFactor;
    const offsetX = (FULL - drawW) / 2;
    const offsetY = (FULL - drawH) / 2;
    /* Composing a layer-wide scale + translate is equivalent to
     * shifting every node into stage coords manually, but is one
     * transform instead of N. Konva applies it in the standard order
     * (scale first, then translate), so the translate values are in
     * STAGE coords, i.e. px — note the `bbox.x * scaleFactor` term. */
    layer.scale({ x: scaleFactor, y: scaleFactor });
    layer.position({
        x: offsetX - bbox.x * scaleFactor,
        y: offsetY - bbox.y * scaleFactor,
    });

    return Promise.all(partPromises).then(function () {
        layer.draw();
        /* PNG (not JPEG) because the thumbnail MUST have a transparent
         * background — it'll be composited over different palette /
         * panel backgrounds in the Quick Add UI and on top of arbitrary
         * room contents at insert time. JPEG has no alpha channel; its
         * flatten-to-background renders empty pixels as black, which
         * looks wrong on every UI surface in the app.
         *
         * Size impact is acceptable: a sparse 100×100 PNG with flat
         * colours compresses to ~5–15 KB. At the MAX_CUSTOM_ITEMS = 200
         * library cap that's ~3 MB worst-case, far inside the IDB
         * per-origin quota (effectively GB-scale).
         *
         * pixelRatio:1 keeps the data URL at exactly 100×100 even on
         * high-DPI displays — devicePixelRatio defaults to whatever the
         * screen reports, which would otherwise inflate the data URL
         * 4× on Retina and produce thumbnails that don't match the
         * receiver's expected size. */
        let dataUrl;
        try {
            dataUrl = stage.toDataURL({ mimeType: 'image/png', pixelRatio: 1 });
        } catch (e) {
            console.warn('[customItemLibrary] toDataURL failed:', e && e.message);
            dataUrl = '';
        }
        try { stage.destroy(); } catch (_) { /* best-effort */ }
        if (container.parentNode) container.parentNode.removeChild(container);
        return dataUrl;
    }).catch(function (e) {
        console.warn('[customItemLibrary] menuImage render failed:', e && e.message);
        try { stage.destroy(); } catch (_) { /* best-effort */ }
        if (container.parentNode) container.parentNode.removeChild(container);
        return '';
    });
}

/* Build + persist a customItem to the VRC Custom Item Library (IDB).
 * Single chokepoint used by:
 *
 *   - createCustomItem()           — initial save on user "Create Custom
 *                                    Item" action (Item 8).
 *   - maybeAutoSaveCustomItemEdit()— auto-update after a canvas edit if
 *                                    the customItem is already in the
 *                                    library (Item 9).
 *   - importCustomItemsFile()      — persist each imported template
 *                                    (Item 11).
 *
 * Resolves to the customItemBaseId on success, or null on any failure.
 * On success also updates the in-memory customItemLibraryIds cache so the
 * itemActionsMenu / Quick Add palette reflect the new state synchronously
 * on the next render. Never throws; failure paths log to console and
 * resolve cleanly — the UX is "best effort", because losing a library
 * save is annoying but not destructive (the customItem still exists on
 * the canvas and can be re-saved). */
function persistCustomItemToLibrary(customItem) {
    if (!customItem || !customItem.customItemBaseId) return Promise.resolve(null);
    if (!window.idbStore || typeof window.idbStore.customItemPut !== 'function') {
        return Promise.resolve(null);
    }

    /* Library invariant: unnamed customItems are CANVAS-ONLY. They live
     * in roomObj.customItems (so undo/redo, save-to-VRC, and shareable
     * URLs all preserve them) but they never enter the VRC Custom Item
     * Library DB. The user has been asked for a name on manual create
     * (openCreateCustomItemDialog) and is nudged for one on export
     * (exportCustomItem), so an unnamed bundle reaching this function
     * means either:
     *   - an import path's auto-save (importer never names, then a
     *     drag/edit fires maybeAutoSaveCustomItemEdit) — silent skip,
     *   - a stale Details-panel edit that cleared the name — silent skip.
     * Either way, persisting an unnamed template would clutter the
     * Quick Add palette with anonymous tiles and confuse the "Add to /
     * Remove from Library" surface. Skipping silently is correct. */
    const cleanName = (customItem.name == null) ? '' : String(customItem.name).trim();
    if (!cleanName) return Promise.resolve(null);

    const record = buildCustomItemExportRecord(customItem);
    if (!record) return Promise.resolve(null);

    return createCustomItemMenuImage(record).then(function (dataUrl) {
        record.menuImage = dataUrl || '';
        record.menuImageVersion = CUSTOM_ITEM_MENU_IMAGE_VERSION;
        return window.idbStore.customItemPut(record);
    }).then(function (savedBaseId) {
        if (savedBaseId) {
            markCustomItemInLibrary(savedBaseId);
            return savedBaseId;
        }
        return null;
    }).catch(function (e) {
        console.warn('[customItemLibrary] persistCustomItemToLibrary failed:', e && e.message);
        return null;
    });
}

/* ---- Quick Add palette: library record cache ----
 *
 * The Quick Add palette (.quick-dialog) re-runs `onQuickAddChange()`
 * on every keystroke against an in-memory list of searchable items.
 * Library customItems must participate in that list, but they live in
 * IndexedDB — fetching from IDB on every keystroke would introduce
 * input lag and burst the IDB transaction queue. Instead we eagerly
 * load all library records into this cache when the Quick Add dialog
 * OPENS (toggleQuickAdd(true) — see hook below), then read from the
 * cache synchronously during search.
 *
 * Cache lifetime: cleared on Quick Add CLOSE (toggleQuickAdd(false))
 * to release the (potentially several MB) menuImage payloads back to
 * the GC. On next open, fresh records are fetched. This keeps the
 * cache from drifting against IDB even across long sessions and
 * cross-tab library mutations.
 *
 * Race condition: if the user types before the IDB fetch completes,
 * `onQuickAddChange` sees an empty cache and shows device-only matches.
 * The fetch's `.then()` re-fires the change handler when records arrive
 * so library tiles appear without further user action. */
let _customItemQuickAddRecordsCache = [];
let _customItemQuickAddRecordsLoading = null; /* in-flight fetch Promise */

function loadCustomItemLibraryRecordsForQuickAdd() {
    if (_customItemQuickAddRecordsLoading) return _customItemQuickAddRecordsLoading;
    if (!window.idbStore || typeof window.idbStore.customItemGetAll !== 'function') {
        _customItemQuickAddRecordsCache = [];
        return Promise.resolve([]);
    }
    _customItemQuickAddRecordsLoading = window.idbStore.customItemGetAll()
        .then(function (records) {
            _customItemQuickAddRecordsCache = Array.isArray(records) ? records : [];
            _customItemQuickAddRecordsLoading = null;
            return _customItemQuickAddRecordsCache;
        })
        .catch(function (e) {
            console.warn('[customItemLibrary] Quick Add fetch failed:', e && e.message);
            _customItemQuickAddRecordsCache = [];
            _customItemQuickAddRecordsLoading = null;
            return [];
        });
    return _customItemQuickAddRecordsLoading;
}

/* Per-baseId debounce timers for maybeAutoSaveCustomItemEdit. A drag of a
 * CustomItem triggers updateCustomItemBounds() on every frame — a naive
 * "persist on every call" would hammer IDB and run the menu-image
 * generator (which spins up a temp Konva stage and decodes every part's
 * topImage) dozens of times per second. The debounce coalesces all of
 * those into a single save 750ms after the user stops editing. The map
 * is keyed by customItemBaseId so concurrent edits to different
 * CustomItems don't cancel each other. */
const _customItemAutoSaveTimers = new Map();
const _CUSTOM_ITEM_AUTO_SAVE_DEBOUNCE_MS = 750;

/* Debounced auto-save of a CustomItem to the VRC Custom Item Library —
 * the "edits to any canvas instance update the IDB record" half of the
 * strict-family model. Only fires for templates that are ALREADY in the
 * library; silently no-ops otherwise, so a roomObj.customItem that the
 * user never explicitly saved (URL-loaded, room-JSON-loaded) doesn't
 * grow the library on every drag.
 *
 * The debounce timer is per customItemBaseId. Concurrent edits to
 * different CustomItems each get their own timer.
 *
 * Edge case — ungroup / delete during the debounce window: when the
 * timer fires we re-look up the CustomItem in roomObj. If it's been
 * dissolved (no longer present, or no longer in the library), the
 * save silently no-ops. Safe.
 *
 * Edge case — feet/meters unit switch during the debounce: handled
 * by buildCustomItemExportRecord which always emits meters regardless
 * of roomObj.unit at save time.
 *
 * No toast on auto-save — drag-and-edit flows are very frequent and
 * a toast per drag would be obnoxious. Only the initial create
 * (createCustomItem) and explicit "Add to Custom Library" / import
 * actions show a toast. */
function maybeAutoSaveCustomItemEdit(customItem) {
    if (!customItem || !customItem.customItemBaseId) return;
    if (!isCustomItemInLibrary(customItem.customItemBaseId)) return;

    const baseId = customItem.customItemBaseId;
    const customitemid = customItem.customitemid;

    const existing = _customItemAutoSaveTimers.get(baseId);
    if (existing) clearTimeout(existing);

    const timer = setTimeout(function () {
        _customItemAutoSaveTimers.delete(baseId);
        /* Re-resolve via the canvas-instance id, not the captured
         * reference — the user may have ungrouped, deleted, or
         * otherwise mutated the customItem during the debounce window. */
        const current = (typeof getCustomItemById === 'function')
            ? getCustomItemById(customitemid)
            : null;
        if (!current) return;
        if (!isCustomItemInLibrary(current.customItemBaseId)) return;
        persistCustomItemToLibrary(current).then(function (saved) {
            if (saved) console.info('[customItemLibrary] auto-saved edit to', saved);
        });
    }, _CUSTOM_ITEM_AUTO_SAVE_DEBOUNCE_MS);

    _customItemAutoSaveTimers.set(baseId, timer);
}

/* "Add to Custom Library" — explicit user opt-in from the itemActionsMenu.
 * Same persist pipeline as createCustomItem's initial save: build record,
 * generate menu image, put to IDB (upserts by baseId so re-clicking is
 * harmless), update the in-memory cache, show toast on success. */
function addCustomItemToLibrary(customItem) {
    if (!customItem) return;
    persistCustomItemToLibrary(customItem).then(function (savedBaseId) {
        if (savedBaseId) showToast('Custom Item saved to library');
    });
}

/* "Remove from Library" — explicit user opt-out. Only deletes the IDB
 * record; the canvas instance is untouched (the customItem still
 * functions as a normal bundle, it just won't appear in the Quick Add
 * palette anymore and edits won't auto-save). The strict-family model
 * means OTHER canvas instances of the same template are also implicitly
 * "not in library" after this call, since membership is keyed by
 * customItemBaseId. */
function removeCustomItemFromLibrary(customItem) {
    if (!customItem || !customItem.customItemBaseId) return;
    if (!window.idbStore || typeof window.idbStore.customItemDelete !== 'function') return;
    const baseId = customItem.customItemBaseId;
    window.idbStore.customItemDelete(baseId).then(function (ok) {
        if (ok) {
            unmarkCustomItemInLibrary(baseId);
            showToast('Custom Item removed from library');
        }
    });
}

/* Opens the "Delete Custom Item" confirmation modal — invoked from the
 * little trash button in the upper-right of each library tile in the
 * Quick Add palette. Mirrors openDeleteLayerDialog() so the surface
 * feels familiar (same dialogWhiteBox style, Cancel/Delete buttons,
 * close-X). On Delete:
 *
 *   - removes the IDB record (idbStore.customItemDelete),
 *   - syncs the in-memory customItemLibraryIds Set so isCustomItemInLibrary()
 *     returns false immediately on subsequent renders (e.g. the
 *     itemActionsMenu re-evaluates the Add/Unjoin entries),
 *   - splices the deleted record out of the Quick Add cache,
 *   - re-fires onQuickAddChange so the deleted tile disappears WITHOUT
 *     wiping the user's current search query, and
 *   - shows a toast for the action.
 *
 * The on-canvas instances of the customItem are intentionally LEFT in
 * place — deletion targets the *library template*, not living bundles
 * the user has placed. That mirrors the wording in the dialog body and
 * matches the strict-family model: instances exist independent of
 * library membership. */
function openDeleteCustomItemFromLibraryDialog(baseId, name) {
    if (!baseId) return;
    const dialog = document.getElementById('dialogCustomItemDelete');
    if (!dialog) return;

    const displayName = (name && String(name).trim().length) ? String(name).trim() : '(unnamed)';
    const safeName = (typeof DOMPurify !== 'undefined') ? DOMPurify.sanitize(displayName) : displayName;
    let html = `<div>Delete <b>"${safeName}"</b> from your local Custom Item Library?</div>`;
    html += `<div style="margin-top: 8px; color: #555;">This only removes the saved template. Existing instances of this Custom Item already on the room canvas are unaffected.</div>`;

    const main = document.getElementById('dialogCustomItemDeleteMain');
    if (main) main.innerHTML = html;

    const btn = document.getElementById('dialogCustomItemDeleteConfirmBtn');
    if (btn) {
        btn.onclick = function () {
            dialog.close();
            if (!window.idbStore || typeof window.idbStore.customItemDelete !== 'function') {
                showToast('Library unavailable — delete failed');
                return;
            }
            window.idbStore.customItemDelete(baseId).then(function (ok) {
                if (!ok) {
                    showToast('Delete failed for "' + displayName + '"');
                    return;
                }
                unmarkCustomItemInLibrary(baseId);
                _customItemQuickAddRecordsCache = (_customItemQuickAddRecordsCache || [])
                    .filter(r => r && r.customItemBaseId !== baseId);
                showToast('Deleted "' + displayName + '" from library');
                const input = document.querySelector('.quick-dialog input');
                if (input) onQuickAddChange({ target: input });
            });
        };
    }
    dialog.showModal();
}

/* "Export Custom Item" — download the customItem as a single-entry
 * .vrcCustomItems.json file and ALSO persist to the IDB library (the
 * user has signalled this is a "keeper" template by exporting it, so
 * library membership is implied). Pre-condition: the customItem must
 * have a non-empty data_labelField (customItem.name), since the file
 * name and downstream UI both display it; export of an unnamed
 * customItem would produce a file the user can't visually distinguish
 * from any other.
 *
 * File naming:
 *   <safe-name>.vrcCustomItems.json
 *
 * Both the .vrcCustomItems infix (matches the JSON discriminator key)
 * and the .json extension (so file pickers recognize it) are kept so
 * the file is both human-identifiable and trivially re-importable.
 *
 * Safe-name filter strips characters that break filesystem semantics
 * on Windows / macOS / Linux paths, mirroring downloadJsonWorkpaceFile. */
function exportCustomItem(customItem) {
    if (!customItem) return;

    const name = (customItem.name || '').trim();
    if (!name) {
        alertDialog(
            'Custom Item Name Required',
            'Please add a Custom Item Name in the Details panel before exporting.'
        );
        return;
    }

    const record = buildCustomItemExportRecord(customItem);
    if (!record) {
        alertDialog(
            'Export Failed',
            'Unable to build an export record for this Custom Item. It may have no members.'
        );
        return;
    }

    createCustomItemMenuImage(record).then(function (dataUrl) {
        record.menuImage = dataUrl || '';
        record.menuImageVersion = CUSTOM_ITEM_MENU_IMAGE_VERSION;

        /* Persist to library — upserts by baseId so re-exporting doesn't
         * duplicate. The library save is best-effort: failure (IDB
         * unavailable, quota exceeded) does NOT block the file download. */
        if (window.idbStore && typeof window.idbStore.customItemPut === 'function') {
            window.idbStore.customItemPut(record).then(function (savedBaseId) {
                if (savedBaseId) markCustomItemInLibrary(savedBaseId);
            });
        }

        /* Build the .vrcCustomItems file payload. Single-entry array now;
         * the format reserves the array shape for future "Export library"
         * workflows that bundle many templates at once. */
        const fileObj = { vrcCustomItems: [record] };
        const json = JSON.stringify(fileObj, null, 2);
        const blob = new Blob([json], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        const safeName = name.replace(/[/\\?%*:|"<>]/g, '-').trim().slice(0, 60) || 'custom_item';
        link.download = safeName + '.vrcCustomItems.json';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);

        showToast('Custom Item exported');
    });
}

/* "Export Custom Items" — Details → Settings entry-point. Bundles
 * EVERY record currently in the local Custom Item Library into a
 * single .vrcCustomItems.json file (same on-the-wire shape as the
 * single-item export — `{ vrcCustomItems: [...] }` — just with N
 * records instead of 1). This is the symmetrical counterpart to the
 * import flow's existing N-record support, so a user can back up,
 * archive, or hand off their entire library in one click.
 *
 * Behaviours:
 *   - Reads the records straight from IDB rather than from the
 *     `_customItemQuickAddRecordsCache`, since the cache is dropped
 *     when the Quick Add dialog closes. The button lives in the
 *     Settings tab where Quick Add isn't open.
 *   - Records are taken VERBATIM from IDB — no re-render of menuImage,
 *     no normalization, no extra IDB writes. The boot migration has
 *     already brought every record up to the current renderer version,
 *     so re-rendering on export would be redundant work.
 *   - Empty-library case is normally prevented by the button's disabled
 *     state, but we still guard at runtime in case the disabled state
 *     drifted (e.g. dev tools clear of IDB while Settings is open).
 *   - "X items exported" is shown via alertDialog (same modal style
 *     used by the import-summary dialog) rather than showToast — the
 *     user just clicked an explicit, infrequent action and benefits
 *     from a synchronous acknowledgement.
 */
function exportAllCustomItemsFromLibrary() {
    if (!window.idbStore || typeof window.idbStore.customItemGetAll !== 'function') {
        alertDialog(
            'Export Failed',
            'Local storage (IndexedDB) is unavailable in this browser session.'
        );
        return;
    }
    window.idbStore.customItemGetAll().then(function (records) {
        if (!Array.isArray(records) || !records.length) {
            alertDialog(
                'No Custom Items',
                'There are no Custom Items in your local library to export.'
            );
            return;
        }
        const fileObj = { vrcCustomItems: records };
        const json = JSON.stringify(fileObj, null, 2);
        const blob = new Blob([json], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        /* Time-stamped filename so multiple exports in a session don't
         * collide in the user's Downloads folder. ISO date (no time) is
         * enough — same-day exports get a -2/-3 suffix from the OS.
         * No PII / no secret material in the filename. */
        const stamp = new Date().toISOString().slice(0, 10); /* YYYY-MM-DD */
        link.download = 'customItemLibrary-' + stamp + '.vrcCustomItems.json';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);

        const n = records.length;
        alertDialog(
            'Custom Items Exported',
            n + ' Custom Item' + (n === 1 ? '' : 's') + ' exported to ' +
            '<code>' + (typeof DOMPurify !== 'undefined' ? DOMPurify.sanitize(link.download) : link.download) + '</code>.'
        );
    }).catch(function (e) {
        console.warn('[customItemLibrary] exportAllCustomItemsFromLibrary failed:', e && e.message);
        alertDialog(
            'Export Failed',
            'Reading the local Custom Item Library failed. See the browser console for details.'
        );
    });
}

/* Toggle the "Export Custom Items" button (Details → Settings) between
 * enabled/disabled based on whether the local library has any records.
 *
 * Source of truth is the in-memory customItemLibraryIds Set, which is
 * kept in sync with IDB by hydrate-on-boot, mark/unmark on save/delete,
 * and the boot menuImage migration. This keeps the call cheap (no IDB
 * round-trip per state-change site) and lets us update the button on
 * every mark/unmark. The button is intentionally hidden behind a
 * standard <button disabled> rather than via .style.display so it's
 * still discoverable in the panel — a user with an empty library can
 * see the affordance, hover for the tooltip, and immediately understand
 * why it isn't actionable yet. */
function updateExportCustomItemsButtonState() {
    const btn = document.getElementById('btnExportAllCustomItems');
    if (!btn) return;
    const count = customItemLibraryIds ? customItemLibraryIds.size : 0;
    btn.disabled = count === 0;
    btn.title = count === 0
        ? 'No Custom Items in the local library yet.'
        : 'Download all ' + count + ' Custom Item' + (count === 1 ? '' : 's') +
          ' as a single .vrcCustomItems.json file.';
}

/* Strict validator for a single .vrcCustomItems record. Returns
 * { valid: true } or { valid: false, error: <string> }.
 * Validation order (cheapest checks first):
 *
 *   1. Required scalar fields: customItemBaseId, width, height.
 *   2. customItemParts must be a non-empty array.
 *   3. Every part needs: data_deviceid, x, y, width, height numbers,
 *      and a known data_deviceid (allDeviceTypes lookup) — an unknown
 *      device kind would crash the inserter and leave a partial
 *      customItem on canvas.
 *
 * data_labelField (the friendly name) is OPTIONAL on the wire — the
 * IDB record will accept '' — but the export path always writes it.
 * menuImage is also optional on the wire; if missing, the import path
 * regenerates one from the parts after insertion (Item 8's pipeline). */
function validateCustomItemRecord(rec) {
    if (!rec || typeof rec !== 'object') return { valid: false, error: 'Not an object' };
    if (typeof rec.customItemBaseId !== 'string' || !rec.customItemBaseId.trim()) {
        return { valid: false, error: 'Missing customItemBaseId' };
    }
    if (typeof rec.width !== 'number' || !isFinite(rec.width) || rec.width <= 0) {
        return { valid: false, error: 'Invalid width' };
    }
    if (typeof rec.height !== 'number' || !isFinite(rec.height) || rec.height <= 0) {
        return { valid: false, error: 'Invalid height' };
    }
    if (!Array.isArray(rec.customItemParts) || !rec.customItemParts.length) {
        return { valid: false, error: 'No customItemParts' };
    }
    for (let i = 0; i < rec.customItemParts.length; i++) {
        const p = rec.customItemParts[i];
        if (!p || typeof p !== 'object') {
            return { valid: false, error: 'Part ' + i + ': not an object' };
        }
        if (typeof p.data_deviceid !== 'string' || !p.data_deviceid.trim()) {
            return { valid: false, error: 'Part ' + i + ': missing data_deviceid' };
        }
        if (typeof p.x !== 'number' || typeof p.y !== 'number' ||
            !isFinite(p.x) || !isFinite(p.y)) {
            return { valid: false, error: 'Part ' + i + ': invalid x/y' };
        }
        if (typeof p.width !== 'number' || typeof p.height !== 'number' ||
            !isFinite(p.width) || !isFinite(p.height)) {
            return { valid: false, error: 'Part ' + i + ': invalid width/height' };
        }
        /* Unknown device kinds are a hard error — we'd have no
         * topImage, no parentGroup, no way to render. Better to
         * surface the bad device id than silently drop the part. */
        if (typeof allDeviceTypes === 'undefined' || !allDeviceTypes[p.data_deviceid]) {
            return { valid: false, error: 'Part ' + i + ': unknown device "' + p.data_deviceid + '"' };
        }
    }
    return { valid: true };
}

/* Materialize a validated customItem export record on the canvas at the
 * center of the active room. Thin wrapper over insertCustomItemAtPosition
 * that supplies room center as the drop point. Kept as its own function
 * so the .vrcCustomItems single-record import branch reads naturally,
 * and so future callers can use the "always center" shape without
 * computing room dimensions. */
function insertCustomItemAtRoomCenter(record) {
    /* Room-center fallback: prefer activeRoomWidth/Length (set when
     * the user has zoomed into a polyRoom part), otherwise use the
     * primary room dimensions. activeRoomX/Y are 0 outside an active
     * room part, so the math works in both cases. */
    const roomW = Number(activeRoomWidth)  || (roomObj.room && Number(roomObj.room.roomWidth))  || 5;
    const roomL = Number(activeRoomLength) || (roomObj.room && Number(roomObj.room.roomLength)) || 5;
    const roomCenterX = (Number(activeRoomX) || 0) + roomW / 2;
    const roomCenterY = (Number(activeRoomY) || 0) + roomL / 2;
    return insertCustomItemAtPosition(record, roomCenterX, roomCenterY);
}

/* Materialize a validated customItem export record on the canvas with
 * its CENTER at (worldX, worldY) in roomObj.unit world coordinates.
 *
 * Counterpart to buildCustomItemExportRecord: meters → roomObj.unit
 * conversion, plus customItem-local → world coords (rotation = 0 on
 * insert, so the rotation step in getPartRenderRect's math collapses
 * to a plain translate).
 *
 * Drop point semantics: (worldX, worldY) is the CENTER of where the
 * bundle should land, not the upper-left. This matches "drop the
 * template here" intent — a user clicking the Quick Add tile at a
 * specific room position expects the bundle to appear AT that
 * position, not extending down-right from it. The upper-left math
 * is internal.
 *
 * Layer assignment: every newly created item AND the customItem rect
 * adopt the value of the "Add Items to:" dropdown (#drpAddItemLayer),
 * matching the per-part insertion convention used elsewhere in the app.
 *
 * No customItem.rotation argument because the inserter always drops the
 * template at rotation 0 — the user is expected to rotate after insert
 * via the canvas controls. Keeps insert behaviour deterministic
 * regardless of how the template was created.
 *
 * Returns the new customitemid on success, or null if no valid members
 * could be materialized (every part's device kind was rejected — rare
 * since validateCustomItemRecord already guards the same condition). */
function insertCustomItemAtPosition(record, worldX, worldY) {
    ensureCustomItems();

    /* Export records store meters; roomObj is in roomObj.unit. */
    const unitFromMeters = (roomObj && roomObj.unit === 'feet') ? 3.28084 : 1;

    const ciW = Number(record.width)  * unitFromMeters;
    const ciH = Number(record.height) * unitFromMeters;
    /* Convert center-drop to upper-left for the internal coordinate
     * math (parts are normalized to a UL-origin frame in the record). */
    const ciX = Number(worldX) - ciW / 2;
    const ciY = Number(worldY) - ciH / 2;

    const layerSel = document.getElementById('drpAddItemLayer');
    const targetLayerId = (layerSel && layerSel.value) || '0';

    const customitemid = createUuid();
    const newMembers = [];

    /* Restore allow-list — mirror of CUSTOM_ITEM_PART_VERBATIM_FIELDS
     * in buildCustomItemExportRecord. Anything not in this set is
     * dropped silently (older or maliciously-edited files could carry
     * arbitrary keys; we don't want them on roomObj items). */
    const RESTORE_VERBATIM = CUSTOM_ITEM_PART_VERBATIM_FIELDS;
    const RESTORE_UNIT_SCALED = CUSTOM_ITEM_UNIT_SCALED_PART_FIELDS;

    record.customItemParts.forEach(part => {
        const dt = allDeviceTypes[part.data_deviceid];
        if (!dt) return; /* validator already rejected, defensive guard */

        const uuid = createUuid();
        const newItem = {
            id: uuid,
            data_deviceid: part.data_deviceid,
            name: dt.name || part.data_deviceid,
            /* CustomItem rotation = 0 on insert, so the inverse of
             * getPartRenderRect's localX/localY transform is a plain
             * translation by the customItem's upper-left. */
            x: ciX + Number(part.x) * unitFromMeters,
            y: ciY + Number(part.y) * unitFromMeters,
            width:  Number(part.width)  * unitFromMeters,
            height: Number(part.height) * unitFromMeters,
            rotation: Number(part.rotation) || 0,
            data_layerId: targetLayerId,
            data_customItemId: customitemid,
        };

        RESTORE_VERBATIM.forEach(f => {
            if (part[f] !== undefined && part[f] !== null) {
                /* Deep clone object fields for the same reason buildCustomItemExportRecord
                 * does — the roomObj item and IDB record share no references. */
                if (typeof part[f] === 'object') {
                    try { newItem[f] = JSON.parse(JSON.stringify(part[f])); }
                    catch (_e) { newItem[f] = part[f]; }
                } else {
                    newItem[f] = part[f];
                }
            }
        });

        RESTORE_UNIT_SCALED.forEach(f => {
            if (typeof part[f] === 'number') newItem[f] = part[f] * unitFromMeters;
        });

        if (typeof part.cornerRadius === 'number') {
            newItem.cornerRadius = part.cornerRadius * unitFromMeters;
        } else if (Array.isArray(part.cornerRadius)) {
            newItem.cornerRadius = part.cornerRadius.map(v => (typeof v === 'number' ? v * unitFromMeters : v));
        }
        if (Array.isArray(part.points)) {
            newItem.points = part.points.map(v => (typeof v === 'number' ? v * unitFromMeters : v));
        }

        const parentGroup = dt.parentGroup;
        if (!parentGroup) return;
        if (!roomObj.items[parentGroup]) roomObj.items[parentGroup] = [];
        roomObj.items[parentGroup].push(newItem);
        newMembers.push(uuid);
    });

    if (!newMembers.length) {
        console.warn('[customItemLibrary] insertCustomItemAtRoomCenter: no members materialized');
        return null;
    }

    /* Use the lowest zPosition among members as the customItem's
     * zPosition — same convention as createCustomItem. */
    let minZ = Infinity;
    newMembers.forEach(uuid => {
        for (const cat in roomObj.items) {
            if (!Array.isArray(roomObj.items[cat])) continue;
            const it = roomObj.items[cat].find(i => i.id === uuid);
            if (it) {
                const z = Number(it.data_zPosition) || 0;
                if (z < minZ) minZ = z;
                break;
            }
        }
    });
    if (!isFinite(minZ)) minZ = 0;

    const newCustomItem = {
        customitemid: customitemid,
        /* Preserve the family / template id so the inserted instance is
         * recognized as "in the library" by isCustomItemInLibrary on
         * the very next render — no awkward "Add to Custom Library"
         * showing on a just-imported template. */
        customItemBaseId: record.customItemBaseId,
        name: String(record.data_labelField || ''),
        data_layerId: targetLayerId,
        x: ciX,
        y: ciY,
        width: ciW,
        height: ciH,
        rotation: 0,
        data_zPosition: minZ,
        customItemMembers: newMembers,
    };

    roomObj.customItems.push(newCustomItem);

    /* Full redraw — mirrors the VRC import path's approach. The
     * customItem rect + member Konva nodes get created by drawRoom
     * walking roomObj. canvasToJson then persists the canvas state
     * to undo history. */
    drawRoom(true, false, false);
    canvasToJson();

    return customitemid;
}

/* Tiny HTML escaper for strings rendered into the import summary
 * dialog via alertDialog (which uses innerHTML). data_labelField is
 * end-user input from arbitrary files, so even though the export
 * path sanitizes on save, we double-escape on display to defend
 * against hand-crafted .vrcCustomItems files. */
function _escapeHtmlForCustomItemDialog(s) {
    return String(s == null ? '' : s)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
}

/* Show the post-import summary dialog. Uses the existing alertDialog()
 * pattern (id=dialogAlertModal) for visual parity with the xConfig
 * import summary — the user already knows this dialog shape.
 *
 * Buckets:
 *   saved:      records newly added to the library (baseId not seen before)
 *   alreadyHad: records whose baseId was already in the library (left
 *               untouched — the existing version wins, see notes in
 *               importCustomItemsFile for the "no surprise overwrite"
 *               rationale)
 *   skippedNoName: records valid by schema but with no data_labelField;
 *               canvas-only per the "unnamed customItems do NOT enter
 *               the Library DB" invariant
 *   failures:   records that failed schema validation or library save
 *
 * insertedOnCanvas: true when the single-record path placed an instance
 *                   in the room canvas. Surfaced as a footnote so the
 *                   user knows where to look. */
function showCustomItemsImportSummaryDialog(saved, alreadyHad, skippedNoName, failures, insertedOnCanvas) {
    const esc = _escapeHtmlForCustomItemDialog;
    const totalAccepted = saved.length + alreadyHad.length + skippedNoName.length;
    const failureCount = failures.length;

    let header;
    if (totalAccepted > 0 && failureCount === 0) {
        header = 'Imported ' + totalAccepted + ' Custom Item' + (totalAccepted === 1 ? '' : 's');
    } else if (totalAccepted === 0 && failureCount > 0) {
        header = 'Custom Item Import Failed';
    } else if (totalAccepted > 0 && failureCount > 0) {
        header = 'Imported ' + totalAccepted + ' Custom Item' + (totalAccepted === 1 ? '' : 's') +
                 ' (' + failureCount + ' failed)';
    } else {
        header = 'No Custom Items in File';
    }

    let body = '';
    if (saved.length) {
        body += '<p><strong>Saved to Library:</strong></p><ul>';
        saved.forEach(s => {
            body += '<li>' + esc(s.name || '(unnamed)') + '</li>';
        });
        body += '</ul>';
    }
    if (alreadyHad.length) {
        body += '<p><strong>Already existed:</strong></p><ul>';
        alreadyHad.forEach(s => {
            body += '<li>' + esc(s.name || '(unnamed)') + '</li>';
        });
        body += '</ul>';
    }
    if (skippedNoName.length) {
        body += '<p><strong>Not saved to Library (no name):</strong></p><ul>';
        skippedNoName.forEach(s => {
            body += '<li>(unnamed)</li>';
        });
        body += '</ul>';
    }
    if (insertedOnCanvas) {
        body += '<p><em>Inserted at the center of the room canvas.</em></p>';
    }
    if (failureCount > 0) {
        body += '<p style="color: #c00;"><strong>Errors:</strong></p><ul style="color: #c00;">';
        failures.forEach(f => {
            body += '<li><strong>' + esc(f.name || '(unnamed)') + '</strong>: ' + esc(f.reason) + '</li>';
        });
        body += '</ul>';
    }

    alertDialog(header, body);
}

/* Top-level entry point for .vrcCustomItems file imports. Routed here
 * from importJson() when the JSON has a `vrcCustomItems` array. Four
 * phases:
 *
 *   1. Validate each record (synchronous, schema-only — no IDB).
 *   2. For each VALID record, check if its customItemBaseId is already
 *      in the library. If yes → bucket as "Already existed" (DO NOT
 *      overwrite; the user's local edits and auto-saves are the source
 *      of truth — re-importing an old export file should never clobber
 *      a fresher local version). If no → bucket as "New, will save".
 *   3. Persist every "new" record that ALSO has a non-empty
 *      data_labelField. Unnamed but valid records become canvas-only —
 *      they're tracked under "Not saved (no name)" and (for the single-
 *      record file path) still inserted on the room canvas.
 *   4. If exactly one valid record was imported, materialize it on the
 *      canvas at room center. The auto-insert fires regardless of
 *      whether the record was saved/skipped/already-had — the user
 *      explicitly dropped a single-item file expecting something
 *      visual to happen.
 *
 * Finally shows the summary dialog with the four buckets. */
function importCustomItemsFile(jsonFile) {
    if (!jsonFile || !Array.isArray(jsonFile.vrcCustomItems)) return;
    const incoming = jsonFile.vrcCustomItems;

    const valid = [];
    const failures = [];
    incoming.forEach((rec, idx) => {
        const v = validateCustomItemRecord(rec);
        if (v.valid) {
            valid.push(rec);
        } else {
            failures.push({
                name: (rec && rec.data_labelField) || ('Entry ' + (idx + 1)),
                reason: v.error,
            });
        }
    });

    if (!valid.length) {
        showCustomItemsImportSummaryDialog([], [], [], failures, false);
        return;
    }

    /* Library is best-effort: if IDB is unavailable, we still surface
     * the failures and (for a single-record file) drop the template
     * on the canvas — the canvas instance works without library
     * membership. */
    const idbAvailable = !!(window.idbStore && typeof window.idbStore.customItemPut === 'function');

    /* Per-record processing:
     *   - hasName: must be non-empty after trim. Unnamed records can
     *              never enter the Library DB (canvas-only invariant).
     *   - alreadyExisted: true if the baseId is already in IDB (via the
     *              in-memory customItemLibraryIds cache, which is
     *              hydrated on boot and kept current by every
     *              mark/unmark). Inside this single import we ALSO add
     *              to a `willSaveBaseIds` Set so a malformed file with
     *              two records sharing one baseId only counts the
     *              second as "Already existed" (matching the
     *              user-visible bucket semantics). */
    const willSaveBaseIds = new Set();
    const toSave = [];
    const alreadyHad = [];
    const skippedNoName = [];

    valid.forEach(rec => {
        const cleanName = (rec.data_labelField == null) ? '' : String(rec.data_labelField).trim();
        const baseId = rec.customItemBaseId;
        const alreadyExists = isCustomItemInLibrary(baseId) || willSaveBaseIds.has(baseId);

        if (alreadyExists) {
            alreadyHad.push({ rec: rec, name: cleanName });
            return;
        }
        if (!cleanName) {
            skippedNoName.push({ rec: rec, name: '' });
            return;
        }
        willSaveBaseIds.add(baseId);
        toSave.push({ rec: rec, name: cleanName });
    });

    /* No library work to do (everything was already-had or unnamed or
     * IDB unavailable) — short-circuit to the summary + auto-insert
     * branch without waiting on Promise.all([]). */
    if (!idbAvailable || !toSave.length) {
        const saved = []; /* nothing actually persisted */
        if (!idbAvailable) {
            /* IDB unavailable — promote every record that WOULD have
             * been saved into the "saved" bucket so the dialog still
             * acknowledges the parse succeeded. They just live only
             * on the canvas this session. */
            toSave.forEach(t => saved.push({ customItemBaseId: t.rec.customItemBaseId, name: t.name }));
        }
        let insertedOnCanvas = false;
        if (valid.length === 1) {
            const inserted = insertCustomItemAtRoomCenter(valid[0]);
            insertedOnCanvas = !!inserted;
        }
        showCustomItemsImportSummaryDialog(saved, alreadyHad, skippedNoName, failures, insertedOnCanvas);
        return;
    }

    const persistPromises = toSave.map(entry => {
        /* The IDB record IS the file payload — same shape — so we put
         * rec directly without reshaping. customItemPut also upserts
         * by baseId; we already gated on "doesn't exist yet" above, so
         * in this branch we expect every put to be a fresh insert. */
        return window.idbStore.customItemPut(entry.rec)
            .then(savedBaseId => ({ entry: entry, savedBaseId: savedBaseId }))
            .catch(_e => ({ entry: entry, savedBaseId: null }));
    });

    Promise.all(persistPromises).then(results => {
        const saved = [];
        results.forEach(r => {
            if (r.savedBaseId) {
                markCustomItemInLibrary(r.savedBaseId);
                saved.push({
                    customItemBaseId: r.savedBaseId,
                    name: r.entry.name,
                });
            } else {
                failures.push({
                    name: r.entry.name || '(unnamed)',
                    reason: 'IDB save failed',
                });
            }
        });

        let insertedOnCanvas = false;
        if (valid.length === 1) {
            const inserted = insertCustomItemAtRoomCenter(valid[0]);
            insertedOnCanvas = !!inserted;
        }

        showCustomItemsImportSummaryDialog(saved, alreadyHad, skippedNoName, failures, insertedOnCanvas);

        /* Toast summary — only when at least one record was newly saved.
         * "Already existed" / "no name" cases don't warrant a toast on
         * top of the dialog; the dialog itself is the loud channel. */
        if (saved.length === 1 && insertedOnCanvas) {
            showToast('Imported 1 Custom Item — saved to library');
        } else if (saved.length > 1) {
            showToast('Imported ' + saved.length + ' Custom Items — saved to library');
        }
    });
}

/* Return all Konva nodes (across all item groups) whose data_customItemId matches customItemId */
function getCustomItemMemberNodes(customItemId) {
    const members = [];
    allNodeShapeGroups.forEach(kg => {
        kg.getChildren().forEach(node => {
            if (node.data_customItemId === customItemId) members.push(node);
        });
    });
    return members;
}

/* Recalculate the CustomItem rect's x, y, width, height from current member
 * positions. Mirrors updateGroupBounds() — see its docstring for the
 * `getMemberBoundingRect` rationale. */
function updateCustomItemBounds(customItemId) {
    if (!groupCustomItemRects) return;
    const members = getCustomItemMemberNodes(customItemId);
    if (!members.length) return;

    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    members.forEach(node => {
        const r = getMemberBoundingRect(node);
        if (r.x < minX) minX = r.x;
        if (r.y < minY) minY = r.y;
        if (r.x + r.width  > maxX) maxX = r.x + r.width;
        if (r.y + r.height > maxY) maxY = r.y + r.height;
    });

    const newX = minX;
    const newY = minY;
    const newW = maxX - minX;
    const newH = maxY - minY;

    const customItemRectNode = groupCustomItemRects.find(n => n.data_customItemId === customItemId)[0];
    if (customItemRectNode) {
        customItemRectNode.x(newX);
        customItemRectNode.y(newY);
        customItemRectNode.width(newW);
        customItemRectNode.height(newH);
    }

    const c = getCustomItemById(customItemId);
    if (c) {
        c.x = ((newX - pxOffset) / scale) + activeRoomX;
        c.y = ((newY - pyOffset) / scale) + activeRoomY;
        c.width  = newW / scale;
        c.height = newH / scale;
        const zPositions = members
            .map(n => parseFloat(n.data_zPosition) || 0)
            .filter(z => !isNaN(z));
        if (zPositions.length) c.data_zPosition = Math.min(...zPositions);

        /* This is called every frame during a drag — the debounce in
         * maybeAutoSaveCustomItemEdit collapses the burst into a single
         * persist 750ms after movement stops. No-op when the template
         * isn't in the library. */
        maybeAutoSaveCustomItemEdit(c);
    }
}

/* Returns { rectNode, customItem, customItemId } when the current selection
 * is exactly one CustomItem's bundle — a single CustomItem rect plus only
 * members of that same customItem, AND no Group rect is in the selection
 * (Group precedence wins). Mirrors getActiveGroupSelection(). */
function getActiveCustomItemSelection(nodes) {
    nodes = nodes || tr.nodes();
    if (!nodes || !nodes.length) return null;
    /* Group precedence: if any Group rect is selected, we are in a Group
     * bundle (or a multi-selection that contains a group rect). The
     * Details panel routes via getActiveGroupSelection() in that case. */
    if (nodes.some(n => n.data_deviceid === 'group')) return null;
    const customItemRects = nodes.filter(n => n.data_deviceid === 'customItem');
    if (customItemRects.length !== 1) return null;
    const rectNode = customItemRects[0];
    const customItemId = rectNode.data_customItemId;
    if (!customItemId) return null;
    const allBelong = nodes.every(n => n === rectNode || n.data_customItemId === customItemId);
    if (!allBelong) return null;
    const customItem = getCustomItemById(customItemId);
    if (!customItem) return null;
    return { rectNode: rectNode, customItem: customItem, customItemId: customItemId };
}

/* Lightweight live-refresh of the CustomItem Details inputs from the
 * rect's current canvas state. Hooked to drag/transform events when a
 * CustomItem is the active selection. Mirrors refreshGroupDetailsFromCanvas(). */
function refreshCustomItemDetailsFromCanvas() {
    const sel = getActiveCustomItemSelection();
    if (!sel) return;
    const r = sel.rectNode;
    const itemX   = document.getElementById('itemX');
    const itemY   = document.getElementById('itemY');
    const itemRot = document.getElementById('itemRotation');
    const itemW   = document.getElementById('itemWidth');
    const itemL   = document.getElementById('itemLength');
    if (itemX)   itemX.value   = round(((r.x() - pxOffset) / scale) + activeRoomX);
    if (itemY)   itemY.value   = round(((r.y() - pyOffset) / scale) + activeRoomY);
    if (itemRot) itemRot.value = round(r.rotation(), -1);
    if (itemW)   itemW.value   = round(r.width()  / scale);
    if (itemL)   itemL.value   = round(r.height() / scale);
}

/* Populate the right-hand Details panel with CustomItem fields when the
 * selection is a single VRC CustomItem. Mirrors populateGroupDetails(). */
function populateCustomItemDetails(rectNode) {
    const customItem = getCustomItemById(rectNode.data_customItemId);
    if (!customItem) return;

    const hideIds = [
        'itemNameDiv', 'labelPathId', 'itemTopElevationDiv', 'itemDiagonalTvDiv',
        'itemVheightDiv', 'trapNarrowWidthDiv', 'tblRectRadiusDiv', 'tblRectRadiusRightDiv',
        'itemTiltSlantDiv', 'itemTiltDiv', 'itemSlantDiv', 'isPrimaryDiv',
        'itemOffsetDiv', 'roleDiv', 'mountDiv', 'colorDiv',
    ];
    hideIds.forEach(id => {
        const el = document.getElementById(id);
        if (el) el.style.display = 'none';
    });

    const showIds = [
        'labelFieldDiv', 'itemLayerDiv', 'itemWidthLengthDiv',
        'itemWidthDiv', 'itemLengthDiv', 'itemRotationDiv',
    ];
    showIds.forEach(id => {
        const el = document.getElementById(id);
        if (el) el.style.display = '';
    });

    document.getElementById('itemLabeldiv').textContent = 'Custom Item Name:';
    document.getElementById('labelField').value = customItem.name || '';

    document.getElementById('itemX').value = round(((rectNode.x() - pxOffset) / scale) + activeRoomX);
    document.getElementById('itemY').value = round(((rectNode.y() - pyOffset) / scale) + activeRoomY);
    document.getElementById('itemZposition').value = (customItem.data_zPosition != null) ? customItem.data_zPosition : 0;

    document.getElementById('itemWidth').value  = round(rectNode.width()  / scale);
    document.getElementById('itemLength').value = round(rectNode.height() / scale);
    document.getElementById('itemWidth').disabled  = true;
    document.getElementById('itemLength').disabled = true;

    document.getElementById('itemRotation').value = round(rectNode.rotation(), -1);

    document.getElementById('itemId').innerText    = customItem.customitemid;
    document.getElementById('itemType').innerText  = 'Custom Item';
    document.getElementById('itemGroup').innerText = '';

    populateLayerDropdown('drpItemLayer', customItem.data_layerId || '0');
}

/* Apply a CustomItem-level edit from the Details panel: X/Y/Z deltas
 * translate every member (and the rect) by the same offset; a rotation
 * delta rotates every member around the CustomItem rect's current visual
 * centre. Mirrors updateGroupItem(). */
function updateCustomItemItem(customItem) {
    if (!customItem || !groupCustomItemRects) return;
    const rectNode = groupCustomItemRects.find(n => n.data_customItemId === customItem.customitemid)[0];
    if (!rectNode) return;

    const newName = (DOMPurify.sanitize(document.getElementById('labelField').value) || '').trim() || customItem.name;
    const newX = Number(document.getElementById('itemX').value) || 0;
    const newY = Number(document.getElementById('itemY').value) || 0;
    const newZ = Number(document.getElementById('itemZposition').value) || 0;
    const newRot = normalizeDegree(Number(document.getElementById('itemRotation').value) || 0);
    const newLayerId = (document.getElementById('drpItemLayer') && document.getElementById('drpItemLayer').value) || '0';

    const currentX_user = ((rectNode.x() - pxOffset) / scale) + activeRoomX;
    const currentY_user = ((rectNode.y() - pyOffset) / scale) + activeRoomY;
    const currentZ      = Number(customItem.data_zPosition) || 0;
    const currentRot    = rectNode.rotation();

    const deltaX_px = (newX - currentX_user) * scale;
    const deltaY_px = (newY - currentY_user) * scale;
    const deltaZ    = newZ - currentZ;
    const deltaR    = newRot - currentRot;

    const members = getCustomItemMemberNodes(customItem.customitemid);

    if (deltaX_px !== 0 || deltaY_px !== 0) {
        members.forEach(m => { m.x(m.x() + deltaX_px); m.y(m.y() + deltaY_px); });
        rectNode.x(rectNode.x() + deltaX_px);
        rectNode.y(rectNode.y() + deltaY_px);
        /* CustomItem move may also need to drag along any Group rect that
         * contains all our members — but only if every member of the
         * Group is also a member of this CustomItem (otherwise the Group
         * would partially de-sync). Skip that case for v1; the user can
         * always select the Group bundle instead to drag everything. */
    }

    if (deltaR !== 0) {
        const centre = getRotatedRectCenter(rectNode);
        members.forEach(m => rotateNodeAroundPoint(m, centre.x, centre.y, deltaR));
        rotateNodeAroundPoint(rectNode, centre.x, centre.y, deltaR);
    }

    if (deltaZ !== 0) {
        members.forEach(m => {
            const existingZ = Number(m.data_zPosition) || 0;
            m.data_zPosition = existingZ + deltaZ;
            if (roomObj && roomObj.items) {
                for (const cat in roomObj.items) {
                    if (!Array.isArray(roomObj.items[cat])) continue;
                    const entry = roomObj.items[cat].find(it => it.id === m.id());
                    if (entry) { entry.data_zPosition = m.data_zPosition; break; }
                }
            }
        });
    }
    customItem.data_zPosition = newZ;
    rectNode.data_zPosition = newZ;

    customItem.name = newName;
    rectNode.data_labelField = newName;

    /* Layer cascade — same share-a-layer invariant Groups enforce. */
    if (newLayerId !== (customItem.data_layerId || '0')) {
        customItem.data_layerId = newLayerId;
        rectNode.data_layerId = newLayerId;
        applyLayerStateToNode(rectNode, newLayerId);
        members.forEach(m => {
            m.data_layerId = newLayerId;
            applyLayerStateToNode(m, newLayerId);
        });
        renderLayersList();
    }

    members.forEach(m => updateShading(m));

    /* No batchDraw() — Konva v8+ auto-redraws on next rAF (see updateGroupItem
     * for the same pattern). Konva.autoDrawEnabled === true. */
    canvasToJson();

    /* If this CustomItem template is in the VRC Custom Item Library,
     * persist the edit (debounced) so the library record stays in sync
     * with the canvas. Defined after canvasToJson() so roomObj is fully
     * reconciled by the time the debounced timer fires and reads it. */
    maybeAutoSaveCustomItemEdit(customItem);

    const btn = document.getElementById("btnUpdateItemId");
    if (btn) {
        btn.disabled = true;
        setTimeout(() => { btn.disabled = false; }, 700);
    }
}

function getDefaultLayers() {
    return [
        { name: 'Default', visible: true, locked: false, layerid: '0' },
        { name: 'Ceiling', visible: true, locked: false, layerid: '1' }
    ];
}

/* Ensure reserved layers '0' and '1' are always present in a layers array */
function ensureDefaultLayers(layers) {
    if (!layers.find(l => l.layerid === '0')) {
        layers.unshift({ name: 'Default', visible: true, locked: false, layerid: '0' });
    }
    if (!layers.find(l => l.layerid === '1')) {
        const idx = layers.findIndex(l => l.layerid === '0');
        layers.splice(idx + 1, 0, { name: 'Ceiling', visible: true, locked: false, layerid: '1' });
    }
}

function getLayerById(layerId) {
    if (!roomObj.layers) return null;
    return roomObj.layers.find(l => l.layerid === layerId) || null;
}

/* Returns true if the given item (or Konva node) is assigned to a hidden VRC layer. */
function isItemInHiddenLayer(itemOrNode) {
    if (!itemOrNode) return false;
    const layerId = itemOrNode.data_layerId || '0';
    const layer = getLayerById(layerId);
    return !!(layer && layer.visible === false);
}

/* Walk the cloned roomObj used by exportRoomObjToWorkspace() and remove every item
 * that belongs to a hidden VRC layer so it is not sent to the Workspace Designer.
 * Mutates the passed object. */
function removeHiddenLayerItemsForExport(roomObj2) {
    if (!roomObj2 || !roomObj2.items || !roomObj.layers) return;
    const hiddenLayerIds = new Set(
        roomObj.layers.filter(l => l.visible === false).map(l => l.layerid)
    );
    if (hiddenLayerIds.size === 0) return;
    for (const group in roomObj2.items) {
        if (!Array.isArray(roomObj2.items[group])) continue;
        roomObj2.items[group] = roomObj2.items[group].filter(item => {
            const lid = item.data_layerId || '0';
            return !hiddenLayerIds.has(lid);
        });
    }
    /* Drop CustomItems whose own layer is hidden too — same rationale
     * as Groups (filtered later in exportRoomObjToWorkspace via the
     * hidden-layer filter on data.vrc.customItems[]). Done here to
     * keep roomObj2 internally consistent. */
    if (Array.isArray(roomObj2.customItems)) {
        roomObj2.customItems = roomObj2.customItems.filter(c => {
            const lid = c.data_layerId || '0';
            return !hiddenLayerIds.has(lid);
        });
    }
}

/* Returns the next available URL layer number (20, 21, ...) for custom layers */
function nextLayerUrlNumber() {
    let used = roomObj.layers
        .filter(l => l.layerid !== '0' && l.layerid !== '1' && l._urlNum != null)
        .map(l => l._urlNum);
    for (let n = 20; ; n++) {
        if (!used.includes(n)) return n;
    }
}

/* Apply a layer's visible/locked state to a Konva node and its coverage nodes
 * (audio~id, speaker~id, fov~id, dispDist~id, label~id).
 *
 * When layer is HIDDEN: all coverage nodes for this item are hidden, regardless of per-item flags.
 * When layer is VISIBLE: coverage nodes are restored according to their per-item flag (data_audioHidden, data_speakerHidden, data_fovHidden, data_dispDistHidden). Labels follow layer visibility (no per-item flag).
 */
function applyLayerStateToNode(node, layerId) {
    if (!layerId || layerId === '') layerId = '0';
    const layer = getLayerById(layerId);
    if (!layer) return;
    if (layer.visible) {
        node.show();
    } else {
        node.hide();
    }
    node.listening(!layer.locked);
    applyLayerLockOpacity(node, layer.locked);
    applyLayerStateToCoverageNodes(node, layer.visible);
}

/* Dim a node to 0.7x of its original opacity when its layer is locked, and restore it
 * to its original opacity when unlocked. The original opacity is captured the first time
 * the node is dimmed (data_originalOpacity) so repeat-locks don't compound the dimming.
 * data_lockOpacityApplied tracks whether we currently hold the dimmed state. */
function applyLayerLockOpacity(node, locked) {
    if (!node || typeof node.opacity !== 'function') return;
    if (locked) {
        if (node.data_lockOpacityApplied !== true) {
            node.data_originalOpacity = node.opacity();
            node.opacity(node.data_originalOpacity * 0.7);
            node.data_lockOpacityApplied = true;
        }
    } else {
        if (node.data_lockOpacityApplied === true) {
            const original = (typeof node.data_originalOpacity === 'number')
                ? node.data_originalOpacity
                : 1;
            node.opacity(original);
            node.data_lockOpacityApplied = false;
            delete node.data_originalOpacity;
        }
    }
}

/* Show/hide the per-item coverage nodes (audio, speaker, fov, dispDist, label)
 * based on layer visibility AND existing per-item hidden flags. */
function applyLayerStateToCoverageNodes(node, layerVisible) {
    const id = node.id();
    if (!id) return;

    const audioNode = stage.findOne('#audio~' + id);
    if (audioNode) {
        audioNode.visible(layerVisible && node.data_audioHidden !== true);
    }

    const speakerNode = stage.findOne('#speaker~' + id);
    if (speakerNode) {
        speakerNode.visible(layerVisible && node.data_speakerHidden !== true);
    }

    const fovNode = stage.findOne('#fov~' + id);
    if (fovNode) {
        fovNode.visible(layerVisible && node.data_fovHidden !== true);
    }

    const dispDistNode = stage.findOne('#dispDist~' + id);
    if (dispDistNode) {
        dispDistNode.visible(layerVisible && node.data_dispDistHidden !== true);
    }

    const labelNode = stage.findOne('#label~' + id);
    if (labelNode) {
        /* Labels have no per-item hidden flag; just respect layer visibility */
        labelNode.visible(layerVisible);
    }
}

/* Re-apply all layer states to every canvas node (called after layer toggle).
 * Also updates the coverage / label layers for each node. */
function applyAllLayerStates() {
    const allNodes = layerTransform.find('Image, Rect, Circle, Shape, Line, Text, RegularPolygon');
    allNodes.forEach(node => {
        if (node.data_layerId) {
            applyLayerStateToNode(node, node.data_layerId);
        }
    });
    /* No explicit batchDraw() needed in Konva v8+ — `Konva.autoDrawEnabled`
     * defaults to true, so the visibility/listening changes above auto-trigger
     * a redraw of layerTransform on the next animation frame.
     *
     * The grShading* / grDisplayDistance / grLabels nodes are Konva.Group
     * children of layerTransform (NOT separate layers), so they ride the
     * same auto-redraw — the previous explicit *.batchDraw() calls were
     * silent no-ops because Konva.Group has no batchDraw method. */
}

/* ---- Layer CRUD ---- */

function addLayer(name) {
    if (!name || name.trim() === '') name = 'New Layer';
    name = DOMPurify.sanitize(name.trim());

    if (isLayerNameDuplicate(name)) {
        name = makeUniqueLayerName(name);
    }
    const urlNum = nextLayerUrlNumber();
    const newLayer = { name: name, visible: true, locked: false, layerid: createUuid(), _urlNum: urlNum };
    roomObj.layers.push(newLayer);
    renderLayersList();
    canvasToJson();
    return newLayer;
}

function deleteLayer(layerId) {
    if (layerId === '0' || layerId === '1') return; /* reserved layers cannot be deleted */

    /* Per UX spec: items in the deleted layer move to the user's currently
     * selected "Add Items to:" target. If that target IS the layer being
     * deleted, reset the dropdown to Default ('0') and move items there. */
    let targetLayerId = currentAddLayerId;
    if (targetLayerId === layerId || !getLayerById(targetLayerId)) {
        currentAddLayerId = '0';
        targetLayerId = '0';
    }

    /* move all items in this layer to the target layer */
    getAllCanvasNodes().forEach(node => {
        if (node.data_layerId === layerId) {
            node.data_layerId = targetLayerId;
            applyLayerStateToNode(node, targetLayerId);
        }
    });
    /* update roomObj items */
    for (const group in roomObj.items) {
        roomObj.items[group].forEach(item => {
            if (item.data_layerId === layerId) {
                if (targetLayerId === '0') {
                    /* Default layer is implicit — omit data_layerId */
                    delete item.data_layerId;
                } else {
                    item.data_layerId = targetLayerId;
                }
            }
        });
    }
    roomObj.layers = roomObj.layers.filter(l => l.layerid !== layerId);
    renderLayersList();
    canvasToJson();
}

function renameLayer(layerId, newName) {
    if (layerId === '0' || layerId === '1') return;
    newName = DOMPurify.sanitize(newName.trim());
    if (!newName) return;
    if (isLayerNameDuplicate(newName, layerId)) {
        alertDialog('Duplicate Layer Name', 'A layer with that name already exists. Please choose a unique name.');
        return false;
    }
    const layer = getLayerById(layerId);
    if (layer) {
        layer.name = newName;
        renderLayersList();
        canvasToJson();
    }
    return true;
}

/* ---- Layer dialog modals (replaces prompt()/confirm()/alert()) ---- */

/* Counts the number of canvas items currently assigned to a given layer.
 * Items without an explicit data_layerId are treated as the Default ('0') layer. */
function countItemsInLayer(layerId) {
    if (typeof layerTransform === 'undefined' || !layerTransform.find) return 0;
    return getAllCanvasNodes().filter(node => {
        const id = node.data_layerId || '0';
        return id === layerId;
    }).length;
}

/* Opens the "Add Layer" modal (replaces the legacy prompt()).
 * Pre-fills the input with a unique default name and focuses it on open. */
function openAddLayerDialog() {
    const dlg = document.getElementById('dialogLayerAdd');
    const input = document.getElementById('layerAddNameInput');
    if (!dlg || !input) return;
    let defaultName = 'New Layer';
    if (typeof isLayerNameDuplicate === 'function' && isLayerNameDuplicate(defaultName)) {
        defaultName = makeUniqueLayerName(defaultName);
    }
    input.value = defaultName;
    dlg.showModal();
    setTimeout(() => { input.focus(); input.select(); }, 0);
}

/* Called by the "Add" button inside dialogLayerAdd. Validates the name
 * against existing layers (showing a follow-up alertDialog on conflict)
 * and creates the layer on success. */
function confirmAddLayerFromDialog() {
    const input = document.getElementById('layerAddNameInput');
    if (!input) return;
    const name = (input.value || '').trim();
    if (!name) {
        alertDialog('Invalid Layer Name', 'Please enter a name for the new layer.');
        return;
    }
    if (typeof isLayerNameDuplicate === 'function' && isLayerNameDuplicate(name)) {
        alertDialog('Duplicate Layer Name', 'A layer with that name already exists. Please choose a unique name.');
        return;
    }
    document.getElementById('dialogLayerAdd').close();
    addLayer(name);
}

/* ---- "Create Custom Item" name-required dialog ----
 *
 * The itemActionsMenu "Create Custom Item" entry routes through this
 * dialog rather than calling createCustomItem() directly so the user
 * is FORCED to supply a non-empty Custom Item name on creation. This
 * preserves the spec invariant that *user-created* customItems always
 * have a name, while still allowing import paths (vrc.json, wd.json,
 * shortened URLs, .vrcCustomItems imports) to deliver unnamed
 * templates — those paths never call createCustomItem at all, they
 * build the customItem record directly on roomObj.
 *
 * Pre-validates the selection BEFORE prompting so the user doesn't
 * waste time typing a name that can't be used (selection too small,
 * stale tr.nodes() after a keyboard deselect mid-menu, etc.). The
 * canCustomItem boolean in toggleItemActionsMenu already disables
 * the menu entry when conditions fail, but a defensive recheck here
 * guards against any race window between menu render and click. */
function openCreateCustomItemDialog() {
    const dlg = document.getElementById('dialogCustomItemAdd');
    const input = document.getElementById('customItemAddNameInput');
    if (!dlg || !input) {
        /* Defensive fallback: if the HTML markup is missing for some
         * reason (older RoomCalculator.html bundled alongside newer
         * roomcalc.js), don't trap the user — surface a clear error
         * instead of silently creating an unnamed customItem (which
         * would violate the "user-created customItems always have a
         * name" invariant). */
        alertDialog('Cannot Create Custom Item',
            'The "Create Custom Item" dialog is unavailable in this build. Please refresh the page.');
        return;
    }

    /* Same selection predicate createCustomItem() will apply.
     * Surfacing the error BEFORE the prompt keeps the UX coherent —
     * no point asking for a name we can't use.
     *
     * Single-item exception mirrors the canCustomItem rule in
     * toggleItemActionsMenu(): a lone `pathShape` is allowed to become
     * a CustomItem on its own. Keep this predicate in lock-step with
     * createCustomItem()'s gate so the dialog never opens for a
     * selection the create function will reject. */
    const candidates = (typeof tr !== 'undefined' && tr && tr.nodes) ? tr.nodes() : [];
    const itemNodes = candidates.filter(n =>
        n.data_deviceid && n.data_deviceid !== 'group' && n.data_deviceid !== 'customItem' && n.isVisible()
    );
    const isSinglePathShape =
        itemNodes.length === 1 && itemNodes[0].data_deviceid === 'pathShape';
    if (itemNodes.length < 2 && !isSinglePathShape) {
        alertDialog('Cannot Create Custom Item',
            'Select at least two items, or a single Custom Path Shape, to create a Custom Item.');
        return;
    }

    input.value = '';
    dlg.showModal();
    /* setTimeout(0) lets <dialog>.showModal complete its open animation
     * before focusing — without this, Chromium sometimes drops the
     * focus on first open. select() is a no-op on empty input but
     * keeps the pattern parity with openAddLayerDialog. */
    setTimeout(() => { input.focus(); input.select(); }, 0);
}

/* Called by the "Create" button (and Enter key) inside
 * dialogCustomItemAdd. Trim + DOMPurify-sanitize the name the same way
 * the Details panel's labelField is sanitized at edit time, so
 * downstream consumers (filenames in exportCustomItem, alertDialog
 * HTML in showCustomItemsImportSummaryDialog) get a uniformly clean
 * value. Empty input after trim is rejected with a follow-up
 * alertDialog rather than silently no-oping, so the user knows why
 * nothing happened. */
function confirmCreateCustomItemFromDialog() {
    const input = document.getElementById('customItemAddNameInput');
    if (!input) return;
    const raw = (input.value || '').trim();
    if (!raw) {
        alertDialog('Custom Item Name Required',
            'Please enter a name for the new Custom Item.');
        return;
    }
    const cleaned = (typeof DOMPurify !== 'undefined' && DOMPurify && typeof DOMPurify.sanitize === 'function')
        ? (DOMPurify.sanitize(raw) || '').trim()
        : raw;
    /* DOMPurify can in theory strip an input down to an empty string
     * (all-script payload). Treat that the same as a blank input — the
     * user needs to provide actual textual content. */
    if (!cleaned) {
        alertDialog('Custom Item Name Required',
            'Please enter a name for the new Custom Item.');
        return;
    }
    const dlg = document.getElementById('dialogCustomItemAdd');
    if (dlg) dlg.close();
    createCustomItem(undefined, cleaned);
}

/* Opens the "Delete Layer" confirmation modal (replaces the legacy confirm()).
 * Shows the layer's name, the number of items it currently contains, the
 * destination layer they will move to, and a notice when the layer is hidden. */
function openDeleteLayerDialog(layerId) {
    if (layerId === '0' || layerId === '1') return; /* reserved layers cannot be deleted */
    const layer = getLayerById(layerId);
    if (!layer) return;

    /* Mirror the destination logic in deleteLayer(): items move to currentAddLayerId,
     * unless that IS the layer being deleted — in which case they go to Default. */
    let destName = 'Default';
    if (currentAddLayerId !== '0' && currentAddLayerId !== layerId) {
        const dest = getLayerById(currentAddLayerId);
        if (dest) destName = dest.name;
    }

    const itemCount = countItemsInLayer(layerId);
    const itemWord = itemCount === 1 ? 'item' : 'items';

    const layerNameSafe = DOMPurify.sanitize(layer.name);
    const destNameSafe = DOMPurify.sanitize(destName);

    let html = `<div>Delete layer <b>"${layerNameSafe}"</b>?</div>`;
    html += `<div style="margin-top: 8px;">${itemCount} ${itemWord} will move to <b>${destNameSafe}</b>.</div>`;
    if (!layer.visible) {
        html += `<div style="margin-top: 8px; color: #b35900;"><i class="icon icon-hide-bold" style="vertical-align: middle;"></i> Note: this layer is currently <b>hidden</b>.</div>`;
    }

    const main = document.getElementById('dialogLayerDeleteMain');
    if (main) main.innerHTML = html;

    const btn = document.getElementById('dialogLayerDeleteConfirmBtn');
    if (btn) {
        btn.onclick = () => {
            document.getElementById('dialogLayerDelete').close();
            deleteLayer(layerId);
        };
    }
    document.getElementById('dialogLayerDelete').showModal();
}

function toggleLayerVisible(layerId) {
    const layer = getLayerById(layerId);
    if (!layer) return;
    layer.visible = !layer.visible;
    applyAllLayerStates();
    /* If the layer is now hidden or still locked, remove its items from current selection */
    if (!layer.visible || layer.locked) {
        removeLayerNodesFromSelection(layerId);
    }
    renderLayersList();
    canvasToJson();
}

function toggleLayerLocked(layerId) {
    const layer = getLayerById(layerId);
    if (!layer) return;
    layer.locked = !layer.locked;
    applyAllLayerStates();
    /* If the layer is now locked or still hidden, remove its items from current selection */
    if (layer.locked || !layer.visible) {
        removeLayerNodesFromSelection(layerId);
    }
    renderLayersList();
    canvasToJson();
}

/* Remove all nodes belonging to the given layer from the current tr selection.
 * Called from Layers-tab Hide/Lock toggles; uses refreshCopyDelBtnState() so the
 * user is not switched off the Layers tab when more than one node remains. */
function removeLayerNodesFromSelection(layerId) {
    const remaining = tr.nodes().filter(n => (n.data_layerId || '0') !== layerId);
    tr.nodes(remaining);
    refreshCopyDelBtnState();
    /* No batchDraw() — Konva v8+ auto-redraws after tr.nodes() change. */
}

/* Toggle visibility for ALL layers (used by global hide/unhide button).
 * If any layer is hidden, show all. Otherwise hide all. */
function toggleAllLayersVisible() {
    if (!roomObj.layers) return;
    const anyHidden = roomObj.layers.some(l => !l.visible);
    const newVisible = anyHidden; /* if any hidden → show all; else hide all */
    roomObj.layers.forEach(l => { l.visible = newVisible; });
    applyAllLayerStates();
    if (!newVisible) {
        /* Hiding all → clear entire selection (stay on Layers tab) */
        tr.nodes([]);
        refreshCopyDelBtnState();
        /* No batchDraw() — Konva v8+ auto-redraws on next rAF. */
    }
    renderLayersList();
    canvasToJson();
}

/* Toggle lock for ALL layers (used by global lock/unlock button).
 * If any layer is locked, unlock all. Otherwise lock all. */
function toggleAllLayersLocked() {
    if (!roomObj.layers) return;
    const anyLocked = roomObj.layers.some(l => l.locked);
    const newLocked = !anyLocked; /* if any locked → unlock all; else lock all */
    roomObj.layers.forEach(l => { l.locked = newLocked; });
    applyAllLayerStates();
    if (newLocked) {
        /* Locking all → clear entire selection (stay on Layers tab) */
        tr.nodes([]);
        refreshCopyDelBtnState();
        /* No batchDraw() — Konva v8+ auto-redraws on next rAF. */
    }
    renderLayersList();
    canvasToJson();
}

function isLayerNameDuplicate(name, excludeLayerId) {
    if (!name) return false;
    const lower = String(name).trim().toLowerCase();
    if (!lower) return false;

    /* Reserved built-in layer names — always considered "taken" so users
     * cannot create or rename a custom layer to "Default" or "Ceiling",
     * even if the reserved entries happen to be missing from roomObj.layers. */
    if (lower === 'default' && excludeLayerId !== '0') return true;
    if (lower === 'ceiling' && excludeLayerId !== '1') return true;

    return roomObj.layers.some(l => l.name.toLowerCase() === lower && l.layerid !== excludeLayerId);
}

function makeUniqueLayerName(baseName) {
    let n = 2;
    let candidate = baseName + ' ' + n;
    while (isLayerNameDuplicate(candidate)) {
        n++;
        candidate = baseName + ' ' + n;
    }
    return candidate;
}

/* Return every draggable/data-carrying Konva node from layerTransform */
function getAllCanvasNodes() {
    return layerTransform.find('Image, Rect, Circle, Shape, Line, RegularPolygon');
}

/* Change a single item's layer by node id.
 *
 * When `nodeId` resolves to a Group rect (data_deviceid === 'group'), the
 * change cascades: every member of the group is moved to `newLayerId`, the
 * group's `data_layerId` in roomObj.groups is updated, and the rect itself is
 * moved too. This keeps the invariant that all members of a Group share a
 * single VRC layer (the same invariant `createGroup()` enforces at create
 * time). Without the cascade, picking a layer in the Group's Details
 * dropdown would only relabel the rect and silently leave the members on
 * their old layer. */
function updateItemLayer(nodeId, newLayerId) {
    if (!newLayerId) newLayerId = '0';
    const node = stage.find('#' + nodeId)[0];
    if (!node) return;

    if (node.data_deviceid === 'group') {
        const groupId = node.data_groupId;
        const group = getGroupById(groupId);
        if (group) group.data_layerId = newLayerId;
        node.data_layerId = newLayerId;
        applyLayerStateToNode(node, newLayerId);
        getGroupMemberNodes(groupId).forEach(m => {
            m.data_layerId = newLayerId;
            applyLayerStateToNode(m, newLayerId);
        });
    } else if (node.data_deviceid === 'customItem') {
        const customItemId = node.data_customItemId;
        const customItem = getCustomItemById(customItemId);
        if (customItem) customItem.data_layerId = newLayerId;
        node.data_layerId = newLayerId;
        applyLayerStateToNode(node, newLayerId);
        getCustomItemMemberNodes(customItemId).forEach(m => {
            m.data_layerId = newLayerId;
            applyLayerStateToNode(m, newLayerId);
        });
    } else {
        node.data_layerId = newLayerId;
        applyLayerStateToNode(node, newLayerId);
    }
    canvasToJson();
    renderLayersList();
}

/* Change layer for all currently selected nodes.
 * Treats "none" (or empty/undefined) as a no-op so users can select multiple items
 * with mixed layers without forcing them all to a single layer until they pick one. */
function updateMultipleItemsLayer(newLayerId) {
    if (!newLayerId || newLayerId === 'none') return;
    tr.nodes().forEach(node => {
        node.data_layerId = newLayerId;
        applyLayerStateToNode(node, newLayerId);
    });
    canvasToJson();
    renderLayersList();
}

/* Select all canvas nodes belonging to a layer */
function selectLayerItems(layerId) {
    const nodes = getAllCanvasNodes().filter(node => {
        const nLayerId = node.data_layerId || '0';
        return nLayerId === layerId;
    });
    if (nodes.length > 0) {
        tr.nodes(nodes);
        enableCopyDelBtn();
        if (nodes.length === 1) {
            updateFormatDetails(nodes[0].id());
        }
    } else {
        tr.nodes([]);
    }
    /* No batchDraw() — Konva v8+ auto-redraws after tr.nodes() change. */
}

/* Layer ID that NEW items (added via the equipment menu, quick-add dialog,
 * polyRoom builder, wall builder, quick-setup, etc.) are assigned to.
 * Driven by the "Add Items to:" dropdown in the Layers tab.
 *
 * Per UX spec: this is a session-only preference — it is NOT persisted in
 * roomObj or the shareable URL, and resets to '0' (Default) on page reload
 * or whenever the selected layer is deleted. */
let currentAddLayerId = '0';

/* Setter wired to the "Add Items to:" dropdown's onchange handler. */
function setCurrentAddLayerId(layerId) {
    currentAddLayerId = (layerId && getLayerById(layerId)) ? layerId : '0';
}

/* Returns the layer id new items should be assigned to. Falls back to
 * '0' (Default) and resets currentAddLayerId if the previously-selected
 * layer no longer exists (e.g., it was just deleted). */
function getDefaultLayerForNewItems() {
    if (currentAddLayerId && getLayerById(currentAddLayerId)) {
        return currentAddLayerId;
    }
    currentAddLayerId = '0';
    return '0';
}

/* Populate the Layers-tab "Add Items to:" dropdown with the current set of
 * layers and select currentAddLayerId. If currentAddLayerId no longer
 * references an existing layer, reset it to '0' (Default) first. */
function populateAddItemLayerDropdown() {
    const sel = document.getElementById('drpAddItemLayer');
    if (!sel) return;
    if (!getLayerById(currentAddLayerId)) currentAddLayerId = '0';
    populateLayerDropdown('drpAddItemLayer', currentAddLayerId);
}

/* Populate a <select> element with current layers.
 * When includeNoneOption is true, a leading blank option with value "none" is added.
 * Used for the multi-item layer dropdown (drpItemLayer2) so a mixed selection can
 * show a blank value, and so picking "none" on update is treated as a no-op. */
function populateLayerDropdown(selectId, selectedLayerId, includeNoneOption) {
    const sel = document.getElementById(selectId);
    if (!sel) return;
    sel.innerHTML = '';

    if (includeNoneOption) {
        const none = document.createElement('option');
        none.value = 'none';
        none.textContent = '';
        if (selectedLayerId === 'none' || selectedLayerId == null) none.selected = true;
        sel.appendChild(none);
    }

    roomObj.layers.forEach(layer => {
        const opt = document.createElement('option');
        opt.value = layer.layerid;
        opt.textContent = layer.name;
        if (layer.layerid === selectedLayerId) opt.selected = true;
        sel.appendChild(opt);
    });
}

/* Render / refresh the Layers tab list and refresh open layer dropdowns */
function renderLayersList() {
    const container = document.getElementById('layersListContainer');
    if (container) {
        container.innerHTML = '';

        /* ---- Global header row (global hide + global lock buttons) ---- */
        const anyHidden = roomObj.layers.some(l => !l.visible);
        const anyLocked = roomObj.layers.some(l => l.locked);

        const headerRow = document.createElement('div');
        headerRow.className = 'layer-row layer-header-row';
        headerRow.dataset.layerid = '__header__';

        /* Global visibility button */
        const globalVisBtn = document.createElement('button');
        globalVisBtn.className = 'layer-icon-btn' + (!anyHidden ? ' layer-btn-active' : '');
        globalVisBtn.title = anyHidden ? 'Show all layers' : 'Hide all layers';
        globalVisBtn.innerHTML = `<i class="icon ${anyHidden ? 'icon-hide-bold' : 'icon-show-bold'}"></i>`;
        globalVisBtn.onclick = () => toggleAllLayersVisible();

        /* Global lock button */
        const globalLockBtn = document.createElement('button');
        globalLockBtn.className = 'layer-icon-btn' + (anyLocked ? ' layer-btn-active layer-btn-locked' : '');
        globalLockBtn.title = anyLocked ? 'Unlock all layers' : 'Lock all layers';
        globalLockBtn.innerHTML = `<i class="icon ${anyLocked ? 'icon-secure-lock-bold' : 'icon-unsecure-unlocked-bold'}"></i>`;
        globalLockBtn.onclick = () => toggleAllLayersLocked();

        const headerLabel = document.createElement('span');
        headerLabel.className = 'layer-name layer-header-label';
        headerLabel.textContent = 'All Layers';

        const headerSpacer = document.createElement('span');
        headerSpacer.className = 'layer-header-spacer';

        headerRow.appendChild(globalVisBtn);
        headerRow.appendChild(globalLockBtn);
        headerRow.appendChild(headerLabel);
        headerRow.appendChild(headerSpacer);
        container.appendChild(headerRow);

        /* ---- Per-layer rows ---- */
        roomObj.layers.forEach(layer => {
            const isReserved = (layer.layerid === '0' || layer.layerid === '1');

            const row = document.createElement('div');
            row.className = 'layer-row';
            row.dataset.layerid = layer.layerid;

            /* visibility button */
            const visBtn = document.createElement('button');
            visBtn.className = 'layer-icon-btn' + (layer.visible ? ' layer-btn-active' : '');
            visBtn.title = layer.visible ? 'Hide layer' : 'Show layer';
            visBtn.innerHTML = `<i class="icon ${layer.visible ? 'icon-show-bold' : 'icon-hide-bold'}"></i>`;
            visBtn.onclick = () => toggleLayerVisible(layer.layerid);

            /* lock button */
            const lockBtn = document.createElement('button');
            lockBtn.className = 'layer-icon-btn' + (layer.locked ? ' layer-btn-active layer-btn-locked' : '');
            lockBtn.title = layer.locked ? 'Unlock layer' : 'Lock layer';
            lockBtn.innerHTML = `<i class="icon ${layer.locked ? 'icon-secure-lock-bold' : 'icon-unsecure-unlocked-bold'}"></i>`;
            lockBtn.onclick = () => toggleLayerLocked(layer.layerid);

            /* layer name — single-click to rename for custom layers */
            const nameSpan = document.createElement('span');
            nameSpan.className = 'layer-name' + (!layer.visible ? ' layer-name-hidden' : '');
            nameSpan.textContent = layer.name;
            if (isReserved) {
                nameSpan.title = 'Reserved layer (cannot be renamed)';
                nameSpan.classList.add('layer-name-reserved');
            } else {
                nameSpan.title = 'Click to rename';
                nameSpan.onclick = (e) => startInlineRename(e, layer.layerid, nameSpan);
            }

            /* delete button */
            const delBtn = document.createElement('button');
            delBtn.className = 'layer-icon-btn layer-delete-btn';
            delBtn.title = isReserved ? 'Reserved layer cannot be deleted' : 'Delete layer';
            delBtn.disabled = isReserved;
            delBtn.innerHTML = `<i class="icon icon-delete-bold"></i>`;
            delBtn.onclick = () => {
                /* Determine the destination layer name for the confirm prompt:
                 * items move to currentAddLayerId, unless that IS the layer
                 * being deleted — in which case they move to Default. */
                let destName = 'Default';
                if (currentAddLayerId !== '0' && currentAddLayerId !== layer.layerid) {
                    const dest = getLayerById(currentAddLayerId);
                    if (dest) destName = dest.name;
                }
                if (confirm(`Delete layer "${layer.name}"? Items will move to ${destName}.`)) {
                    deleteLayer(layer.layerid);
                }
            };

            row.appendChild(visBtn);
            row.appendChild(lockBtn);
            row.appendChild(nameSpan);
            row.appendChild(delBtn);
            container.appendChild(row);
        });
    } /* end if (container) */

    /* refresh layer dropdowns in Details panels if visible */
    const singleSel = document.getElementById('drpItemLayer');
    if (singleSel) {
        const cur = singleSel.value;
        populateLayerDropdown('drpItemLayer', cur);
    }
    const multiSel = document.getElementById('drpItemLayer2');
    if (multiSel) {
        const cur2 = multiSel.value;
        populateLayerDropdown('drpItemLayer2', cur2, true);
    }

    /* refresh the Layers-tab "Add Items to:" dropdown so it always reflects
     * the current set of layers and the active currentAddLayerId */
    populateAddItemLayerDropdown();
}

/* Inline rename via single-click on a custom layer's name span (reserved layers are not editable) */
function startInlineRename(e, layerId, nameSpan) {
    e.stopPropagation();
    const currentName = nameSpan.textContent;
    const input = document.createElement('input');
    input.type = 'text';
    input.value = currentName;
    input.className = 'layer-name-input';
    nameSpan.replaceWith(input);
    input.focus();
    input.select();

    function commit() {
        const newName = input.value.trim();
        if (newName && newName !== currentName) {
            const ok = renameLayer(layerId, newName);
            if (!ok) {
                input.replaceWith(nameSpan);
            }
        } else {
            input.replaceWith(nameSpan);
        }
    }

    input.onblur = commit;
    input.onkeydown = (ev) => {
        if (ev.key === 'Enter') { commit(); ev.preventDefault(); }
        if (ev.key === 'Escape') { input.replaceWith(nameSpan); ev.preventDefault(); }
    };
}

let defaultRoomSurfaces = {
    leftwall: { type: 'regular', acousticTreatment: true },
    videowall: { type: 'regular', acousticTreatment: false },
    rightwall: { type: 'regular', acousticTreatment: false },
    backwall: { type: 'regular', acousticTreatment: false }
}

roomObj.roomSurfaces = structuredClone(defaultRoomSurfaces);


let unit = roomObj.unit;

let gridToggleState = 'room';
let toggleButtonOnColor = '#4169E1';

let toggleButtonOffColor = '#800000';

let undoArray = [];

let redoArray = [];

