function createKonvaBackgroundImageFloor(x = pxOffset - 5, y = pyOffset - 5, height = stage.height() * 1.05, opacity = 0.5) {

    /* remove previous instances of the background image */
    let tempKonvaBackgroundImageFloor = getKonvaBackgroundImageFloor();

    if (tempKonvaBackgroundImageFloor) {
        tempKonvaBackgroundImageFloor.destroy();
    }

    let konvaBackgroundImageFloor = new Konva.Image({
        image: backgroundImageFloor,
        x: x,
        y: y,
        height: height,
        opacity: opacity,
        id: 'konvaBackgroundImageFloor',
        listening: false
    });

    konvaBackgroundImageFloor.data_deviceid = 'backgroundImageFloor';

    konvaBackgroundImageFloor.on('dragend', function konvaBackgroundImageFloorOnDragend() {
        canvasToJson();
    });

    return konvaBackgroundImageFloor;
}


/* tr is the Transformer that does the selection and rotation magic for Konva.  It exists in its own group. */
let tr = new Konva.Transformer({
    resizeEnabled: false,
    flipEnabled: false,
    rotationSnaps: [0, 45, 90, 135, 180, 225, 270, 315, 360],
    name: 'theTransformer',
    rotateAnchorOffset: 25,
});

tr.on('dragstart', function trDragStart() {


    if (tr.nodes().length > 100) {

        hideAllCoverageGroups(true);
    }


});

tr.on('dragmove', function trDragMove() {

    /* When the user drags the Transformer's bounding box (rather than a
     * single member) Konva moves every node in tr.nodes() natively and the
     * per-member dragmove handlers don't always fire — push the live rect
     * coords into the bundle Details panel so X/Y track the drag. */
    refreshGroupDetailsFromCanvas();
    refreshCustomItemDetailsFromCanvas();
});

tr.on('dragend', function trDragStart() {

    hideAllCoverageGroups(false);
    endGroupDragFollow();
    endCustomItemDragFollow();
    /* Final flush of the bundle Details panel after a Transformer-driven
     * drag (catches missed-frame edge cases). */
    refreshGroupDetailsFromCanvas();
    refreshCustomItemDetailsFromCanvas();
});

/* Customize the rotation / rotater anchor */
const rotateImageObj = new Image();

rotateImageObj.onload = function rotateImageObjOnload() {

    tr.anchorStyleFunc((anchor) => {
        updateRotaterAnchor(anchor);
    })
};

function updateRotaterAnchor(anchor) {
    if (anchor.attrs.name.startsWith('rotater')) {

        anchor.height(20);
        anchor.offsetY(10);
        anchor.width(20);
        anchor.offsetX(10);
        anchor.cornerRadius(anchor.width() / 2);
        anchor.stroke('lightblue');
        anchor.fill('');
        anchor.fillPatternImage(rotateImageObj);
        anchor.fillPatternOffset({ x: 0, y: 0 });

    }
}

