function createTemplateButton(template) {
    const { name, url, note, noteUrl, image } = template;
    const box = document.createElement('div');
    box.className = 'room-template';
    const button = document.createElement('button');
    const label = document.createElement('span');
    label.innerText = name;
    button.className = 'templateLinks';
    button.onclick = () => loadTemplate(url);
    box.appendChild(button);

    const img = document.createElement('img');
    img.src = `./assets/images/templates/${image}`;
    img.inert = true; /* used to remove the Edge image search */
    /* `.room-template img` defaults to a fixed 122 × 120 footprint so
     * the tile reserves its space before the image bytes have decoded
     * (avoids the thin vertical-line flash). Once the image actually
     * loads, the `.loaded` class drops the width back to `auto` so each
     * thumbnail renders at its own aspect ratio (the original look —
     * fixed height, width fits the image). The `complete` short-circuit
     * handles the case where the browser served the image straight from
     * cache and the load event has already fired by the time we get
     * here. */
    const markImgLoaded = () => img.classList.add('loaded');
    if (img.complete && img.naturalWidth > 0) {
        markImgLoaded();
    } else {
        img.addEventListener('load', markImgLoaded, { once: true });
    }
    button.appendChild(img);

    button.appendChild(label);

    if (note) {
        const a = document.createElement('a');
        a.innerText = note;
        a.href = noteUrl;
        a.target = '_blank';
        a.className = 'infoText';
        box.appendChild(a);
    }

    return box;
}

function populateTemplates() {
    const parent = document.querySelector('#room-templates');
    /* RoomCalculator.html seeds 9 `.room-template-placeholder` tiles
     * inside `#room-templates` so the dialog has the right grid size on
     * the very first frame (before templates.js has finished loading).
     * Replace those placeholders in-place with the real tiles so layout
     * stays stable; templates beyond the 9th get appended; any unused
     * placeholders (templates.length < 9) are dropped. */
    const placeholders = Array.from(parent.querySelectorAll('.room-template-placeholder'));
    templates.forEach((template, idx) => {
        const tile = createTemplateButton(template);
        const ph = placeholders[idx];
        if (ph) {
            parent.replaceChild(tile, ph);
        } else {
            parent.appendChild(tile);
        }
    });
    for (let i = templates.length; i < placeholders.length; i++) {
        placeholders[i].remove();
    }
    /* Real templates are now in the DOM — drop the blur from the
     * placeholders' loading state. */
    parent.classList.remove('templates-loading');
    /* The "Reload last design" tile is added by the caller
     * (`openNewRoomDialog()`) via `ensureTemplatesPopulated().then()`
     * so it lands AFTER the placeholders have been swapped out — that
     * way it doesn't get inserted next to loading placeholders and
     * visually bounce when the real templates pop in. */
}

/* Single-flight lazy loader for templates.js + populateTemplates(). The
 * first openNewRoomDialog() call kicks this off; the modal shows
 * synchronously and the templates pop into the grid as soon as the
 * script finishes loading (typically a few ms from disk cache). Repeat
 * calls return the same Promise so the templates are never double-added
 * to the DOM. On load failure the promise is cleared so the next dialog
 * open retries. */
let _templatesPopulationPromise = null;
function ensureTemplatesPopulated() {
    if (_templatesPopulationPromise) return _templatesPopulationPromise;
    _templatesPopulationPromise = loadScriptOnce(VRC.constants.SCRIPT_TEMPLATES)
        .then(() => {
            populateTemplates();
        })
        .catch(err => {
            _templatesPopulationPromise = null;
            console.error('Failed to load templates.js for new-room dialog', err);
        });
    return _templatesPopulationPromise;
}

/* Show or hide the "Reload last design" tile in the new-room dialog's
 * templates grid based on:
 *   1. `newRoomDialogOpenCount <= 1` — this is still the very first time
 *      the dialog is appearing on this page load. After the user closes
 *      and reopens the dialog the tile is removed.
 *   2. `priorUndoArrayHasData` — at page load the localStorage `undoArray`
 *      held at least one design from a previous session, so undoing the
 *      freshly-loaded default room actually restores something meaningful.
 *   3. `!roomLoadedFromXQuery` — the room was NOT loaded from a `?x=`
 *      shareable link. When the user opened a specific shared design we
 *      don't want a one-click "undo" tile that would silently replace
 *      that design with their own previous-session work.
 *
 * Clicking the tile closes the dialog and triggers `btnUndoClicked()` —
 * since `saveToUndoArray()` already pushed the default room onto the
 * stack at startup, the single undo pops the default and restores the
 * user's previous design. */
function syncReloadLastDesignButton() {
    const parent = document.querySelector('#room-templates');
    if (!parent) return;
    const existing = document.getElementById('btnReloadLastDesign');

    const shouldShow = (newRoomDialogOpenCount <= 1)
        && priorUndoArrayHasData
        && !roomLoadedFromXQuery;
    if (!shouldShow) {
        if (existing) existing.remove();
        return;
    }
    if (existing) {
        /* Already present — make sure it's at the front in case templates
         * were appended after it. */
        if (parent.firstChild !== existing) {
            parent.insertBefore(existing, parent.firstChild);
        }
        return;
    }

    const box = document.createElement('div');
    box.id = 'btnReloadLastDesign';
    box.className = 'room-template';

    const button = document.createElement('button');
    button.className = 'templateLinks';
    button.title = 'Reload last design';
    button.onclick = () => {
        closeNewRoomDialog();
        reloadLastNonEmptyDesign();
    };

    const iconWrap = document.createElement('div');
    iconWrap.className = 'reloadLastDesignIconWrap';
    const i = document.createElement('i');
    i.className = 'icon icon-undo-regular reloadLastDesignIcon';
    iconWrap.appendChild(i);
    button.appendChild(iconWrap);

    const label = document.createElement('span');
    label.innerText = 'Reload last design';
    button.appendChild(label);

    box.appendChild(button);
    parent.insertBefore(box, parent.firstChild);
}

/* True iff `obj.items` exists and at least one of its array fields
 * (videoDevices, chairs, tables, …) contains at least one entry.
 * Iterating over the object's own keys keeps this future-proof: any new
 * `roomObj.items.<group>` array added later is automatically covered. */
function roomObjHasAnyItems(obj) {
    if (!obj || !obj.items) return false;
    for (const key in obj.items) {
        if (!Object.prototype.hasOwnProperty.call(obj.items, key)) continue;
        const arr = obj.items[key];
        if (Array.isArray(arr) && arr.length > 0) return true;
    }
    return false;
}

/* Click handler for the "Reload last design" tile.
 *
 * One call to `btnUndoClicked()` pops the freshly-saved default room
 * (pushed by `saveToUndoArray()` during `onLoad()`) and restores the
 * previous design. If THAT design is itself empty (e.g. the user closed
 * a brand-new tab without ever adding anything), keep walking back
 * through `undoArray` until we find a design that actually contains
 * items — or hit the same boundary the toolbar undo button does
 * (`undoArray.length === 1`, beyond which there is nothing left to
 * restore). The loop is bounded by `undoArray` shrinking by one each
 * iteration, so it cannot run away. */
function reloadLastNonEmptyDesign() {
    btnUndoClicked();
    while (undoArray.length > 1 && !roomObjHasAnyItems(roomObj)) {
        btnUndoClicked();
    }
}

