/* Get the element with id="defaultOpen" and click on it */
function toggleButton(button) {
    if (button.style['color'] === 'black') {
        button.style["color"] = 'grey'
    } else {
        button.style["color"] = 'black'
    };
}

/* shows an undo dialog and adds a delay on undo / redo on RoomOS devices */
function showUndoRedoRoomOs() {

    let undoTime = 350;


    if (mobileDevice === 'RoomOS') {
        undoTime = 500;
        document.getElementById('dialogUndoRedo').style.display = '';
    } else {
        document.getElementById('dialogUndoRedo').style.display = 'none';
    }

    document.getElementById('dialogUndoRedo').showModal();

    setTimeout(() => {
        document.getElementById('dialogUndoRedo').close();
    }, undoTime);
}

function showNewRoomSection(sectionId) {
    const showTemplates = sectionId === 'room-templates';
    document.querySelector('#room-templates').style.display = showTemplates ? 'flex' : 'none'
    document.querySelector('#quick-setup').style.display = !showTemplates ? 'flex' : 'none'

    document.querySelector('#roomTemplateBtn').className = showTemplates ? 'buttonHighlight' : '';
    document.querySelector('#quickSetupBtn').className = !showTemplates ? 'buttonHighlight' : '';

}

function onDialogClick(e) {
    const clickedOutside = e.target.tagName === 'DIALOG'
    if (clickedOutside) {
        e.target.close()
        closeAllDialogModals();
    }
}

function openSaveDialog() {
    document.getElementById('dialogSave').showModal();

    let qrCodeDiv = document.getElementById('qrCode');
    if ((mobileDevice === 'RoomOS' || qrCodeAlwaysOn || mobileDevice === 'Tesla')) {

        if (!qrCodeDiv.hasChildNodes()) {
            loadQRCodeScript();
        } else {
            createShareableLink();
        }

    }

}

function openNewRoomDialog() {
    document.getElementById('roomWidth2').value = roomObj.room.roomWidth;
    document.getElementById('roomLength2').value = roomObj.room.roomLength;
    document.getElementById('roomName2').value = roomObj.name;
    /* Track every dialog open. The "Reload last design" tile is gated
     * on `newRoomDialogOpenCount <= 1` so it only appears the very first
     * time the dialog is shown on this page load (whether auto-shown
     * during onLoad() or manually opened by the user). */
    newRoomDialogOpenCount++;
    /* Lazy-load templates.js + populate the grid on first open. The
     * modal shows synchronously below; templates pop in a moment later
     * by replacing the seeded `.room-template-placeholder` tiles. */
    const populated = ensureTemplatesPopulated();
    /* Defer the "Reload last design" tile until the real templates are
     * in place. If we called `syncReloadLastDesignButton()` synchronously
     * here, the tile would be inserted alongside the loading
     * placeholders and then visually bounce around as the real
     * templates pop in. On subsequent opens this promise is already
     * resolved so the call effectively runs synchronously. */
    populated.then(() => {
        syncReloadLastDesignButton();
    });
    document.getElementById('newRoomDialog').showModal();
}

function closeNewRoomDialog() {
    document.getElementById('newRoomDialog').close();
}

function openQuestionDialog() {
    document.getElementById('dialogQuestions').showModal();
}

function closeDialogQuestions() {
    document.getElementById('dialogQuestions').close();
}

function btnUndoClicked() {

    if (!(polyBuilderMode === 'none' || polyBuilderMode === '')) {
        closeAllDialogModals();
        polyBuilderOn(false);
        updateItem();
        return;
    };


    showUndoRedoRoomOs();
    zoomInOut('reset');

    clearTimeout(undoArrayTimer);
    if (undoArray.length > 0) {
        const movedEntry = undoArray.pop();
        redoArray.push(movedEntry);
        roomObj = structuredClone(undoArray[undoArray.length - 1]);
        unit = roomObj.unit;
        drawRoom(true, true, true);
        enableBtnUndoRedo();
        setTimeout(() => {
            createShareableLink();
        }, 750);

        /* Mirror the in-memory pop onto IDB so a refresh resumes at the same
         * position in the undo timeline. Fire-and-forget. */
        if (typeof window !== 'undefined' && window.idbStore) {
            window.idbStore.undoPopLast();
            window.idbStore.redoAdd(structuredClone(movedEntry));
        }

        /* If this restored snapshot references a library image, fetch the
         * Blob and re-apply it. No-op if the same image was already loaded
         * or the snapshot has no image. */
        if (typeof rehydrateBackgroundImageFromIdb === 'function') {
            rehydrateBackgroundImageFromIdb();
        }
    }
}

function btnRedoClicked() {

    if (!(polyBuilderMode === 'none' || polyBuilderMode === '')) {
        closeAllDialogModals();
        polyBuilderOn(false);
        updateItem();
        return;
    };

    showUndoRedoRoomOs()
    zoomInOut('reset');

    if (redoArray.length > 0) {
        const movedEntry = redoArray.pop();
        undoArray.push(movedEntry);
        roomObj = structuredClone(undoArray[undoArray.length - 1]);
        drawRoom(true, true, true);
        setTimeout(() => {
            createShareableLink();

        }, 500);

        /* Mirror onto IDB so a refresh resumes at the same position. */
        if (typeof window !== 'undefined' && window.idbStore) {
            window.idbStore.redoPopLast();
            window.idbStore.undoAdd(structuredClone(movedEntry));
        }

        /* See btnUndoClicked() — same rehydrate logic for redo. */
        if (typeof rehydrateBackgroundImageFromIdb === 'function') {
            rehydrateBackgroundImageFromIdb();
        }
    }
    enableBtnUndoRedo();
}

function enableBtnUndoRedo() {
    if (undoArray.length > 1) {
        document.getElementById('btnUndo').disabled = false;
    } else {
        document.getElementById('btnUndo').disabled = true;
    }
    if (redoArray.length > 0) {
        document.getElementById('btnRedo').disabled = false;
    } else {
        document.getElementById('btnRedo').disabled = true;
    }
}

let canvasClipBoard = {};

function copyToCanvasClipBoard(nodes) {
    let itemsObj = { unit: roomObj.unit }

    if (!nodes) nodes = tr.nodes();

    let uuids = [];

    let clipBoardArray = [];

    /* ---- Group / CustomItem selection bookkeeping ----
     * A bundle (group or customItem) is "complete" when its rect AND every
     * current member are in the selection. Only complete bundles
     * round-trip through the clipboard with their structure intact:
     * members keep data_groupId / data_customItemId (remapped on paste)
     * and a fresh rect is materialized on paste. Members of incomplete
     * bundles paste as ungrouped/uncustom-itemed, mirroring the URL/WD-
     * import rule that empty / partial bundles are dropped.
     * expandSelectionForGroups() normally guarantees complete bundles,
     * but this is the defensive backstop. */
    const selectedRectGroupIds = new Set();
    const selectedMemberIdsByGroup = {};
    const selectedRectCustomItemIds = new Set();
    const selectedMemberIdsByCustomItem = {};
    nodes.forEach(n => {
        if (n.data_deviceid === 'group' && n.data_groupId) {
            selectedRectGroupIds.add(n.data_groupId);
        } else if (n.data_deviceid === 'customItem' && n.data_customItemId) {
            selectedRectCustomItemIds.add(n.data_customItemId);
            /* Defensive: a CustomItem rect can also carry a data_groupId
             * in legacy buggy state — pre-May-2026 createGroup didn't filter
             * customItem rects out of itemNodes, so they ended up in
             * group.groupMembers AND got tagged with data_groupId. Without
             * this branch, the completeness check below would reject the
             * Group (its groupMembers includes the CustomItem rect's UUID,
             * but the rect goes into selectedRectCustomItemIds rather than
             * selectedMemberIdsByGroup) and the Group would be silently
             * dropped from the clipboard. The paste path's "rebuild
             * groupMembers from new item uuids" pass naturally drops the
             * stale CustomItem-rect UUID, so this rescue is also a
             * cleanup — pasted Group ends up with only real items as
             * members. */
            if (n.data_groupId) {
                (selectedMemberIdsByGroup[n.data_groupId] = selectedMemberIdsByGroup[n.data_groupId] || new Set()).add(n.id());
            }
        } else {
            if (n.data_groupId) {
                (selectedMemberIdsByGroup[n.data_groupId] = selectedMemberIdsByGroup[n.data_groupId] || new Set()).add(n.id());
            }
            if (n.data_customItemId) {
                (selectedMemberIdsByCustomItem[n.data_customItemId] = selectedMemberIdsByCustomItem[n.data_customItemId] || new Set()).add(n.id());
            }
        }
    });
    const completeGroupIds = new Set();
    selectedRectGroupIds.forEach(gid => {
        const group = getGroupById(gid);
        if (!group) return;
        const present = selectedMemberIdsByGroup[gid] || new Set();
        const allHere = (group.groupMembers || []).every(id => present.has(id));
        if (allHere) completeGroupIds.add(gid);
    });
    const completeCustomItemIds = new Set();
    selectedRectCustomItemIds.forEach(cid => {
        const customItem = getCustomItemById(cid);
        if (!customItem) return;
        const present = selectedMemberIdsByCustomItem[cid] || new Set();
        const allHere = (customItem.customItemMembers || []).every(id => present.has(id));
        if (allHere) completeCustomItemIds.add(cid);
    });

    nodes.forEach(node => {
        /* Group rect: emit a special clipboard entry so pasteItems() can
         * mint a fresh roomObj.groups entry with a remapped groupid and
         * recreate the rect. Skip the regular item-attr pipeline (the
         * rect has no Konva.Image, no diagonal/role/colour/etc., and its
         * canonical x/y/width/height live in roomObj.groups, not on the
         * Konva attrs in unit space). */
        if (node.data_deviceid === 'group') {
            const oldGroupId = node.data_groupId;
            if (!completeGroupIds.has(oldGroupId)) return;
            const group = getGroupById(oldGroupId);
            if (!group) return;
            clipBoardArray.push({
                isGroupRect: true,
                oldGroupId: oldGroupId,
                groupAttrs: {
                    name: group.name,
                    data_layerId: group.data_layerId || '0',
                    data_zPosition: parseFloat(group.data_zPosition) || 0,
                    x: group.x || 0,
                    y: group.y || 0,
                    width: group.width || 0,
                    height: group.height || 0,
                    rotation: group.rotation || 0,
                },
            });
            return;
        }

        /* CustomItem rect: same pattern as the Group rect above.
         * customItemBaseId is preserved verbatim across copy/paste —
         * the strict-family rule means every canvas instance of the
         * same template shares one baseId, so a duplicated CustomItem
         * remains "the same template" in the IDB library. Only the
         * per-instance customitemid is remapped (in pasteItems). */
        if (node.data_deviceid === 'customItem') {
            const oldCustomItemId = node.data_customItemId;
            if (!completeCustomItemIds.has(oldCustomItemId)) return;
            const customItem = getCustomItemById(oldCustomItemId);
            if (!customItem) return;
            clipBoardArray.push({
                isCustomItemRect: true,
                oldCustomItemId: oldCustomItemId,
                customItemAttrs: {
                    name: customItem.name,
                    customItemBaseId: customItem.customItemBaseId || null,
                    data_layerId: customItem.data_layerId || '0',
                    data_zPosition: parseFloat(customItem.data_zPosition) || 0,
                    x: customItem.x || 0,
                    y: customItem.y || 0,
                    width: customItem.width || 0,
                    height: customItem.height || 0,
                    rotation: customItem.rotation || 0,
                },
            });
            return;
        }

        let x2Offset, y2Offset, x2, y2; /* new x and new y */
        let attrs = node.attrs;

        let uuid = createUuid();

        uuids.push(uuid);

        if (!('rotation' in attrs)) {
            node.rotation(0);
        }

        let rotation = attrs.rotation;
        let center = {};

        if (node.getParent().name() === 'tables' || node.getParent().name() === 'stageFloors' || node.getParent().name() === 'boxes' || node.getParent().name() === 'rooms') {
            center.x = node.x();
            center.y = node.y();
        } else {
            center = getNodeCenter(node);
        }

        x2Offset = 0;
        y2Offset = 0;

        x2 = ((center.x - pxOffset) / scale) + x2Offset / scale;
        y2 = ((center.y - pyOffset) / scale) + y2Offset / scale;


        let width = attrs.width / scale;
        let height = attrs.height / scale;
        let deviceId = node.data_deviceid;
        let newAttr = { x: x2, y: y2, width: width, height: height, rotation: rotation };

        if ('points' in attrs) {
            let newPoints = [];
            attrs.points.forEach((point, index) => {
                newPoints[index] = point / scale;
            });

            newAttr.points = newPoints;
        }

        if ('data_diagonalInches' in node) {
            newAttr.data_diagonalInches = node.data_diagonalInches;
        }

        if ('data_zPosition' in node) {
            newAttr.data_zPosition = node.data_zPosition;
        }

        if ('data_vHeight' in node) {
            newAttr.data_vHeight = node.data_vHeight;
        }

        if ('cornerRadius' in node.attrs) {
            if (node.attrs.cornerRadius.length > 1) {
                newAttr.tblRectRadius = node.attrs.cornerRadius[2] / scale;
            }

            if (node.attrs.cornerRadius[0] != node.attrs.cornerRadius[2]) {
                newAttr.tblRectRadiusRight = node.attrs.cornerRadius[0] / scale;
            }
        }

        if ('data_labelField' in node) {
            newAttr.data_labelField = node.data_labelField;
        }

        if ('data_fovHidden' in node) {
            newAttr.data_fovHidden = node.data_fovHidden;
        }

        if ('item.data_audioHidden' in node) {
            newAttr.data_audioHidden = node.data_audioHidden
        }

        if ('data_role' in node) {
            newAttr.data_role = node.data_role;
        }

        if ('data_color' in node) {
            newAttr.data_color = node.data_color;
        }

        if ('data_mount' in node) {
            newAttr.data_mount = node.data_mount;
        }

        if ('data_tilt' in node) {
            newAttr.data_tilt = node.data_tilt;
        }

        if ('data_slant' in node) {
            newAttr.data_slant = node.data_slant;
        }

        if ('data_trapNarrowWidth' in node && !isNaN(node.data_trapNarrowWidth)) {
            newAttr.data_trapNarrowWidth = node.data_trapNarrowWidth;
        }

        if ('data_layerId' in node && node.data_layerId) {
            newAttr.data_layerId = node.data_layerId;
        }

        /* Group membership — only carried for members of "complete" group
         * selections (rect + all members present). pasteItems() remaps
         * this old groupid to the freshly minted one. Drop it for
         * incomplete groups so those members paste as ungrouped. */
        if (node.data_groupId && completeGroupIds.has(node.data_groupId)) {
            newAttr.data_groupId = node.data_groupId;
        }

        /* CustomItem membership — same rule as Group above. */
        if (node.data_customItemId && completeCustomItemIds.has(node.data_customItemId)) {
            newAttr.data_customItemId = node.data_customItemId;
        }

        clipBoardArray.push({ deviceId: deviceId, parent: node.getParent().name(), newAttr: newAttr, uuid: createUuid() });

    });

    itemsObj.items = clipBoardArray;
    canvasClipBoard.items = clipBoardArray;


    /* get transform (tr) upper left hand corner in pixels and adjust for zoom, pan and scale.  */
    let canvasPixelX = (tr.x() + dx) / zoomScaleX;
    let canvasPixelY = (tr.y() + dy) / zoomScaleY;

    let unitX = (canvasPixelX - pxOffset) / scale;
    let unitY = (canvasPixelY - pxOffset) / scale;

    canvasClipBoard.upperLeft = { x: unitX, y: unitY };

    canvasClipBoard.sessionId = sessionId;
    canvasClipBoard.unit = roomObj.unit;
    setItemForLocalStorage('copyItemsObj', JSON.stringify(canvasClipBoard));


}

/* allow copying items between tabs / windows of the same browsers */
window.addEventListener("storage", () => {
    canvasClipBoard = JSON.parse(localStorage.getItem('copyItemsObj'));
});

/* when the ctrl+C / cmd+C shortcut is used */
function copyItems() {
    copyToCanvasClipBoard();
}

/* when the ctrl+X / cmd+X shortcut is used */
function cutItems() {
    copyToCanvasClipBoard();
    deleteTrNodes();
}

loadLastCopyItem();

/* when copying items between tabs/windows, allows for a newly opened tab/window to have a copy of the Canvas Clipboard */
function loadLastCopyItem() {
    let newCanvasClipBoard = JSON.parse(localStorage.getItem('copyItemsObj'));
    if (newCanvasClipBoard) {
        canvasClipBoard = newCanvasClipBoard;
    }
}




/* paste item in canvasClipBoard to canvas.  if duplicate = true, offset from current object. If duplicate = false, paste at the mouse arrow location */
function pasteItems(duplicate = true) {
    tr.nodes([]);
    let itemsObj = structuredClone(canvasClipBoard);
    let xOffset = 0, yOffset = 0;
    if (itemsObj.unit) {

        if (roomObj.unit != itemsObj.unit) {
            let newItems = [];
            let ratio = 3.28084;
            if (roomObj.unit === 'feet') {
                ratio = ratio;
            } else {
                ratio = 1 / ratio;
            }

            itemsObj.items.forEach((item, index) => {
                /* Group / CustomItem rect entries carry their dims in
                 * `groupAttrs` / `customItemAttrs` (unit space) instead of
                 * `newAttr`. All three bags share the same
                 * x/y/width/height/data_zPosition keys that
                 * convertItemUnitBasedOnRatio handles. */
                if (item.isGroupRect) {
                    item.groupAttrs = convertItemUnitBasedOnRatio(item.groupAttrs, ratio);
                } else if (item.isCustomItemRect) {
                    item.customItemAttrs = convertItemUnitBasedOnRatio(item.customItemAttrs, ratio);
                } else {
                    item.newAttr = convertItemUnitBasedOnRatio(item.newAttr, ratio);
                }
            });

        }

        /* Skip Group / CustomItem rect entries — they have no
         * allDeviceTypes mapping and the codec-count check only cares
         * about regular items. */
        checkForMultipleCodecsOnPaste(itemsObj.items.filter(it => !it.isGroupRect && !it.isCustomItemRect));

    } else {
        return;
    }

    /* ---- Build oldGroupId → newGroupId map ----
     * Every Group rect in the clipboard mints a fresh groupid; member
     * items that were copied alongside a Group rect get their
     * data_groupId remapped below. Members whose old groupid is NOT in
     * the map (no rect copied → incomplete group) paste as ungrouped. */
    const oldToNewGroupId = {};
    const oldToNewCustomItemId = {};
    itemsObj.items.forEach(it => {
        if (it.isGroupRect && it.oldGroupId) {
            oldToNewGroupId[it.oldGroupId] = createUuid();
        }
        if (it.isCustomItemRect && it.oldCustomItemId) {
            oldToNewCustomItemId[it.oldCustomItemId] = createUuid();
        }
    });

    let uuids = [];

    if (duplicate) {


        if (itemsObj.items.length === 1 && !itemsObj.items[0].isGroupRect && !itemsObj.items[0].isCustomItemRect && itemsObj.items[0].deviceId.startsWith('chair')) {
            let itemAttr = itemsObj.items[0].newAttr;
            let offset = (roomObj.unit === 'feet') ? 2.35 : 2.35 / 3.28084;
            let rotation = itemAttr.rotation;
            if (rotation === 180) {
                offset = offset * -1;
            }
            if (rotation < 0) {
                offset = offset * -1;
            };

            let newLocation = findNewTransformationCoordinate({ x: itemAttr.x, y: itemAttr.y, rotation: rotation }, offset, 0);
            xOffset = itemAttr.x - newLocation.x;
            yOffset = itemAttr.y - newLocation.y;


        } else {
            xOffset = (stage.width() * 0.04) / scale;
            yOffset = (stage.height() * 0.04) / scale;
        }


    } else if (mouseUnit.x < (unit === 'feet' ? -1.5 : -0.45) || mouseUnit.y < (unit === 'feet' ? -1.5 : -0.45) || mouseUnit.x > (roomObj.room.roomWidth * 1.04) || mouseUnit.y > (roomObj.room.roomLength * 1.04)) {
        /* if the mouse is off the canvas, don't paste */
        return;
    } else {
        /* adjust paste offset based on tr captured location compared to the current mouse location. */
        xOffset = mouseUnit.x - itemsObj.upperLeft.x;
        yOffset = mouseUnit.y - itemsObj.upperLeft.y;
    }


    /* Track new member uuids per new groupid / customitemid so we can
     * populate groupMembers / customItemMembers on the freshly minted
     * roomObj.groups / roomObj.customItems entries. */
    const newMembersByGroupId = {};
    const newMembersByCustomItemId = {};

    itemsObj.items.forEach(item => {

        if (item.isGroupRect) return; /* materialized in the second pass below */
        if (item.isCustomItemRect) return; /* materialized in the second pass below */

        /* if pasted item references a layer that no longer exists, assign to Default */
        if (item.newAttr.data_layerId && item.newAttr.data_layerId !== '0' && item.newAttr.data_layerId !== '1') {
            if (!getLayerById(item.newAttr.data_layerId)) {
                item.newAttr.data_layerId = '0';
            }
        }

        /* Remap data_groupId: complete-group members point at the new
         * groupid; members of incomplete groups (no rect in clipboard)
         * paste as ungrouped. */
        if (item.newAttr.data_groupId) {
            const newGid = oldToNewGroupId[item.newAttr.data_groupId];
            if (newGid) {
                item.newAttr.data_groupId = newGid;
            } else {
                delete item.newAttr.data_groupId;
            }
        }

        /* Same remap for data_customItemId. */
        if (item.newAttr.data_customItemId) {
            const newCid = oldToNewCustomItemId[item.newAttr.data_customItemId];
            if (newCid) {
                item.newAttr.data_customItemId = newCid;
            } else {
                delete item.newAttr.data_customItemId;
            }
        }

        let uuid = createUuid();
        uuids.push(uuid);
        item.newAttr.x = item.newAttr.x + xOffset;
        item.newAttr.y = item.newAttr.y + yOffset;
        itemCount++;
        insertShapeItem(item.deviceId, item.parent, item.newAttr, uuid);

        if (item.newAttr.data_groupId) {
            (newMembersByGroupId[item.newAttr.data_groupId] = newMembersByGroupId[item.newAttr.data_groupId] || []).push(uuid);
        }
        if (item.newAttr.data_customItemId) {
            (newMembersByCustomItemId[item.newAttr.data_customItemId] = newMembersByCustomItemId[item.newAttr.data_customItemId] || []).push(uuid);
        }

    })


    /* ---- Second pass: materialize each pasted Group ----
     * Pushes a fresh entry into roomObj.groups (with the remapped
     * groupid, the offset top-left, and groupMembers populated from the
     * uuids generated above) and inserts a new Group rect on the canvas
     * via insertGroupRect(). The rect's groupid is added to `uuids` so
     * trNodesFromUuids() selects the whole bundle (rect + members) — the
     * same selection shape the user had before copying. */
    itemsObj.items.forEach(item => {
        if (!item.isGroupRect) return;
        const newGroupId = oldToNewGroupId[item.oldGroupId];
        if (!newGroupId) return;
        ensureGroups(roomObj);

        let layerId = item.groupAttrs.data_layerId || '0';
        if (layerId !== '0' && layerId !== '1' && !getLayerById(layerId)) {
            layerId = '0';
        }

        const newGroup = {
            groupid: newGroupId,
      //       name: item.groupAttrs.name || ('Group ' + (roomObj.groups.length + 1)),
            name: item.groupAttrs.name || (''), 
            data_layerId: layerId,
            x: (item.groupAttrs.x || 0) + xOffset,
            y: (item.groupAttrs.y || 0) + yOffset,
            width: item.groupAttrs.width || 0,
            height: item.groupAttrs.height || 0,
            rotation: item.groupAttrs.rotation || 0,
            data_zPosition: parseFloat(item.groupAttrs.data_zPosition) || 0,
            groupMembers: newMembersByGroupId[newGroupId] || [],
        };

        roomObj.groups.push(newGroup);
        insertGroupRect(newGroup);
        uuids.push(newGroupId);
    });

    /* ---- Third pass: materialize each pasted CustomItem ----
     * Mirror of the Group pass above. */
    itemsObj.items.forEach(item => {
        if (!item.isCustomItemRect) return;
        const newCustomItemId = oldToNewCustomItemId[item.oldCustomItemId];
        if (!newCustomItemId) return;
        ensureCustomItems(roomObj);

        let layerId = item.customItemAttrs.data_layerId || '0';
        if (layerId !== '0' && layerId !== '1' && !getLayerById(layerId)) {
            layerId = '0';
        }

        const newCustomItem = {
            customitemid: newCustomItemId,
            /* Preserve the family / template id verbatim from the
             * clipboard — see copyToCanvasClipBoard()'s CustomItem rect
             * branch for the strict-family rule. Falls back to a fresh
             * UUID for clipboard payloads minted before this field
             * existed (mixed-session paste). */
            customItemBaseId: item.customItemAttrs.customItemBaseId || createUuid(),
            name: item.customItemAttrs.name || '',
            data_layerId: layerId,
            x: (item.customItemAttrs.x || 0) + xOffset,
            y: (item.customItemAttrs.y || 0) + yOffset,
            width: item.customItemAttrs.width || 0,
            height: item.customItemAttrs.height || 0,
            rotation: item.customItemAttrs.rotation || 0,
            data_zPosition: parseFloat(item.customItemAttrs.data_zPosition) || 0,
            customItemMembers: newMembersByCustomItemId[newCustomItemId] || [],
        };

        roomObj.customItems.push(newCustomItem);
        insertCustomItemRect(newCustomItem);
        uuids.push(newCustomItemId);
    });


    trNodesFromUuids(uuids, true);  /* select the newly pasted items */

    // stage.draw();

}




