                if (width2 > width) {
                        width2 = width;
                }



                ctx.beginPath();
                ctx.moveTo(0, 0);
                ctx.lineTo(width, 0);
                ctx.lineTo((width / 2) + (width2 / 2), height);
                ctx.lineTo((width / 2) - (width2 / 2), height);
