let rightClickMenuDialogId = 'rightClickMenuId';
let mouseOverRightClickMenu = false; /* is the mouse over the rightclick menu */


function closeRightClickMenu() {
    let element = document.getElementById(rightClickMenuDialogId);
    if (element) {
        element.remove();
    } /* if the menu already exists, remove and recreate */
}


/* -----------------------------------------------------------------
 * Per-item Group / CustomItem ellipse menu
 * -----------------------------------------------------------------
 * Built dynamically next to #btnUpdateItemId or #btnMultiUpdateItemId
 * via the .itemEllipseBtn buttons in RoomCalculator.html. Opens with
 * a fixed-position popover anchored to the clicked button. The menu
 * contents are computed from the current `tr.nodes()` state, NOT
 * from which button was clicked — this keeps single-vs-multi rules
 * aligned with the right-click menu's Group/Ungroup logic, and
 * scopes "Custom Item" actions to the same selection rules.
 *
 * Per the design (Option 1, May 2026): CustomItem actions live ONLY
 * on this menu, NOT on the right-click context menu. Only `Group` /
 * `Ungroup` are duplicated between the two surfaces.
 *
 * The menu is fixed-position so it floats over the rest of the
 * Details panel; clicking outside or pressing Escape closes it.
 */
const ITEM_ACTIONS_MENU_ID = 'itemActionsMenu';

function closeItemActionsMenu() {
    const el = document.getElementById(ITEM_ACTIONS_MENU_ID);
    if (el) el.remove();
    document.removeEventListener('mousedown', _itemActionsMenuOutsideClick, true);
    document.removeEventListener('keydown',   _itemActionsMenuKeydown,      true);
}

function _itemActionsMenuOutsideClick(e) {
    const el = document.getElementById(ITEM_ACTIONS_MENU_ID);
    if (!el) return;
    /* Don't close when the user clicks the menu itself or one of the
     * ellipse buttons (the button's own onclick handles toggle). */
    if (el.contains(e.target)) return;
    if (e.target.closest && e.target.closest('.itemEllipseBtn')) return;
    closeItemActionsMenu();
}

function _itemActionsMenuKeydown(e) {
    if (e.key === 'Escape') closeItemActionsMenu();
}

function toggleItemActionsMenu(event, mode) {
    if (event) {
        event.preventDefault();
        event.stopPropagation();
    }

    /* Toggle off if already open */
    if (document.getElementById(ITEM_ACTIONS_MENU_ID)) {
        closeItemActionsMenu();
        return;
    }

    const anchorBtn = (event && event.currentTarget) ||
        (mode === 'multi'
            ? document.getElementById('btnMultiUpdateItemEllipse')
            : document.getElementById('btnUpdateItemEllipse'));
    if (!anchorBtn) return;

    /* ---- Selection introspection ----
     * Build the same canGroup / canUngroup booleans used by the
     * right-click menu (see createRightClickMenu lines ~27515-27521)
     * so the two surfaces stay in lock-step. CustomItem booleans are
     * computed here only — they don't appear on the right-click menu. */
    const trNodes = (typeof tr !== 'undefined' && tr && tr.nodes) ? tr.nodes() : [];

    const itemsOnly = trNodes.filter(n =>
        n.data_deviceid !== 'group' && n.data_deviceid !== 'customItem');

    const distinctGroupIds = new Set(itemsOnly.map(n => n.data_groupId || null));
    const allSameExistingGroup = (distinctGroupIds.size === 1 && !distinctGroupIds.has(null));

    const distinctCustomItemIds = new Set(itemsOnly.map(n => n.data_customItemId || null));
    const allSameExistingCustomItem = (distinctCustomItemIds.size === 1 && !distinctCustomItemIds.has(null));

    /* Compute the single-CustomItem-bundle predicate up front — it
     * gates both "Unjoin Custom Item" (enabled only when it's true)
     * and "Create Group" (disabled when it's true; see below). Hoisted
     * above canGroup so the boolean is in scope for both decisions. */
    const activeCustomItemSel = getActiveCustomItemSelection(trNodes);
    const singleCustomItemBundleSelected = !!activeCustomItemSel;

    /* Group creation is disabled when:
     *   - fewer than 2 real items are selected, OR
     *   - all items already share the same Group (no-op — would just
     *     dissolve and recreate the existing Group), OR
     *   - the selection is *exactly* one CustomItem bundle and nothing
     *     else. The bundle is already a logical grouping; wrapping it
     *     in a Group around just itself would produce a redundant
     *     1-CustomItem Group with no other members. Mixed selections
     *     (CustomItem bundle + an outside item) still allow Group
     *     creation, per the architectural rule "a Group can have
     *     CustomItems, but a CustomItem cannot have Groups". The
     *     CustomItem rect tags along on Group drags via
     *     `getCustomItemRectsAllInGroup()`. */
    const canGroup = itemsOnly.length >= 2 && !allSameExistingGroup && !singleCustomItemBundleSelected;
    const canUngroup = trNodes.some(n => n.data_deviceid === 'group' || n.data_groupId);

    /* CustomItem creation rules: 2+ items selected, not already all in
     * the same single CustomItem (would just dissolve and recreate the
     * existing CustomItem). Existing `data_groupId` on the members does
     * NOT block creation — `createCustomItem()` enforces "a CustomItem
     * cannot have Groups" by dissolving every touched Group as part of
     * the create, so any nested Group state is stripped from the new
     * bundle.
     *
     * Single-item exception: a single `pathShape` is also allowed to
     * become a CustomItem on its own. Custom Path Shapes are
     * user-authored geometry that the user often wants to bundle (and
     * save to the library) as a standalone reusable template — the
     * "2+ items" rule that prevents redundant 1-item bundles for normal
     * devices doesn't make sense for these. The same
     * `!allSameExistingCustomItem` check still gates re-bundling an
     * already-bundled pathShape. */
    const isSinglePathShape =
        itemsOnly.length === 1 && itemsOnly[0].data_deviceid === 'pathShape';
    const canCustomItem =
        (itemsOnly.length >= 2 || isSinglePathShape) && !allSameExistingCustomItem;

    /* "Unjoin Custom Item" is offered only when the selection is *exactly*
     * one CustomItem bundle and nothing else — i.e. the same condition
     * that drives the "Custom Item Name:" Details panel via
     * `getActiveCustomItemSelection()`. That helper already enforces:
     *   - no Group rect in the selection (Group bundle wins),
     *   - exactly one CustomItem rect,
     *   - every other selected node is a member of that CustomItem.
     * Tying the menu state to the same predicate keeps the surface
     * coherent: if you can see "Custom Item Name:" you can remove it,
     * and vice versa. Multi-CustomItem selections, mixed selections,
     * and bare CustomItem-member selections (no rect) all fail this
     * test — by design, the user is expected to first click into the
     * specific bundle they want to dissolve. */
    const canUncustomItem = singleCustomItemBundleSelected;

    /* ---- Build menu DOM ---- */
    const menu = document.createElement('div');
    menu.id = ITEM_ACTIONS_MENU_ID;

    const addItem = (label, disabled, onClick) => {
        const div = document.createElement('div');
        div.className = disabled ? 'itemActionsMenuItemDisable' : 'itemActionsMenuItem';
        div.textContent = label;
        if (!disabled) {
            div.addEventListener('click', () => {
                closeItemActionsMenu();
                try { onClick(); } catch (err) { console.error(err); }
            });
        }
        menu.appendChild(div);
    };

    const addDivider = () => {
        const hr = document.createElement('hr');
        hr.className = 'itemActionsMenuDivider';
        menu.appendChild(hr);
    };

    addItem('Create Group',       !canGroup,        () => createGroup());
    addItem('Ungroup',            !canUngroup,      () => ungroupSelectedItems());
    addDivider();
    addItem('Create Custom Item', !canCustomItem,   () => openCreateCustomItemDialog());
    addItem('Unjoin Custom Item', !canUncustomItem, () => ungroupSelectedCustomItems());

    /* ---- Single-CustomItem-bundle actions ----
     * The Export / library actions ONLY appear when the selection is
     * exactly one CustomItem bundle (rect + all its members). We
     * reuse getActiveCustomItemSelection's strict predicate — same
     * one that gates the Details panel's "Custom Item Name:" field —
     * so the three surfaces (right-click menu, Details panel, this
     * popover) stay in lock-step about what counts as "the currently
     * focused Custom Item".
     *
     * Library membership is read synchronously from the in-memory
     * customItemLibraryIds Set (hydrated from IDB on page load).
     * Showing "Add to Custom Library" or "Remove from Library" is
     * mutually exclusive based on isCustomItemInLibrary; the third
     * action (Export) is always shown when a single CustomItem is
     * selected — its own pre-check (must have a name) is enforced
     * inside exportCustomItem() with an alertDialog if missing.
     *
     * Re-uses `activeCustomItemSel` hoisted above the canGroup
     * computation (single source of truth for "is the selection
     * exactly one CustomItem bundle?"). */
    if (activeCustomItemSel && activeCustomItemSel.customItem) {
        const sel = activeCustomItemSel.customItem;
        const baseId = sel.customItemBaseId;
        const inLibrary = isCustomItemInLibrary(baseId);
        addDivider();
        addItem('Export Custom Item', false, () => exportCustomItem(sel));
        if (inLibrary) {
            addItem('Remove from Library', false, () => removeCustomItemFromLibrary(sel));
        } else {
            addItem('Add to Custom Library', false, () => addCustomItemToLibrary(sel));
        }
    }

    /* ---- Position & mount ----
     * Fixed-position popover anchored just below the ellipse button.
     * Pinned to the button's right edge so the menu hugs the panel's
     * right side, then nudged left if it would clip the viewport.
     * Mount first so we can measure the rendered width. */
    document.body.appendChild(menu);

    const btnRect = anchorBtn.getBoundingClientRect();
    const menuRect = menu.getBoundingClientRect();

    let left = btnRect.right - menuRect.width;
    if (left + menuRect.width > window.innerWidth - 4) {
        left = Math.max(4, window.innerWidth - menuRect.width - 4);
    }
    if (left < 4) left = 4;

    let top = btnRect.bottom + 4;
    if (top + menuRect.height > window.innerHeight - 4) {
        /* Flip above the button when there isn't room below */
        top = Math.max(4, btnRect.top - menuRect.height - 4);
    }

    menu.style.left = left + 'px';
    menu.style.top  = top  + 'px';

    /* Close on outside click or Escape — capture phase so we beat any
     * click handlers inside the panel itself. */
    document.addEventListener('mousedown', _itemActionsMenuOutsideClick, true);
    document.addEventListener('keydown',   _itemActionsMenuKeydown,      true);
}


/* createas a right click menu */
function createRightClickMenu(usePreviousPosition = false) {

    if (isMeasuringToolOn) return;

    let previousXY = {};
    quickAddMouse.x = mouseUnit.x;
    quickAddMouse.y = mouseUnit.y;



    let element = document.getElementById(rightClickMenuDialogId);

    if (element && element.open) {

        element.close();
        return;
    }

    if (element) {

        element.remove();
    } /* if the menu already exists, remove and recreate */


    mouseOverRightClickMenu = false;

    let bottomBuffer = 256;
    let rightBuffer = 277;

    if (mobileDevice === 'RoomOS') {
        bottomBuffer = 380;
    }

    selecting = false; /* selecting rectangle should not be used */

    let rightClickMenuDialog = document.createElement('div');
    rightClickMenuDialog.id = rightClickMenuDialogId;
    rightClickMenuDialog.className = 'rightClickMenu';


    let rightClickMenuDiv = document.createElement('div');
    rightClickMenuDiv.id = 'rightClickMenuDiv';
    rightClickMenuDiv.className = 'rightClickMenuDiv';


    document.body.appendChild(rightClickMenuDialog); /* Adds to the end of the body, but shows up as a dialog modal where the arrow is located */

    rightClickMenuDialog.appendChild(rightClickMenuDiv);
    /* if dialog and showModal() use the following */

    let mouseX = mouse.x;
    let mouseY = mouse.y;

    if (window.innerHeight - bottomBuffer < mouseY) {
        mouseY = window.innerHeight - bottomBuffer;
    }

    if (window.innerWidth - rightBuffer < mouseX) {
        mouseX = window.innerWidth - rightBuffer;
    }

    let newX = mouseX;
    let newY = mouseY;

    if (usePreviousPosition) {
        newX = rightClickMenuDialogLastPosition.x;
        newY = rightClickMenuDialogLastPosition.y;
    }

    const pos = stage.getPointerPosition();
    const shape = layerTransform.getIntersection(pos);

    let hr = document.createElement('hr');
    hr.className = 'rightClickHorizontalLine';


    rightClickMenuDiv.textContent = '';

    if (!isMeasuringToolOn) {
        createMenuItem('copyMenuDiv', 'Copy', 'ctrl+c', tr.nodes().length < 1);
        createMenuItem('pasteMenuDiv', 'Paste', 'ctrl+p', !Object.keys(canvasClipBoard).length || false);
        createMenuItem('deleteMenuDiv', 'Delete', 'delete', tr.nodes().length < 1);
        createMenuItem('duplicateMenuDiv', 'Duplicate', 'ctrl+d', tr.nodes().length < 1);
        rightClickMenuDiv.appendChild(hr.cloneNode(true));
        createMenuItem('quickAddMenu', 'Quick Add', 'space', false);
        rightClickMenuDiv.appendChild(hr.cloneNode(true));
        createMenuItem('zoomResetDiv', 'Zoom 100%', '', (zoomValue === 100));
        rightClickMenuDiv.appendChild(hr.cloneNode(true));
        createMenuItem('rotateDiv', 'Rotate 90°', 'ctrl+r', tr.nodes().length < 1)
        rightClickMenuDiv.appendChild(hr.cloneNode(true));
        /* Group is enabled when there are 2+ real items in the selection AND
         * they are not already all members of the same single Group.
         * Excludes both Group rects AND CustomItem rects — neither becomes
         * a Group member (`createGroup()` filters them both out of
         * `finalNodes`); counting them here would mis-enable the menu when
         * only one real item is selected alongside a CustomItem rect.
         *
         * CustomItem state intentionally does NOT block Group creation: a
         * Group can wrap one or more CustomItems (the items keep their
         * `data_customItemId` and additionally get the new `data_groupId`).
         * Matches the ellipse-menu equivalent in `toggleItemActionsMenu()`. */
        const itemsOnly = tr.nodes().filter(n =>
            n.data_deviceid !== 'group' && n.data_deviceid !== 'customItem');
        const distinctGroupIds = new Set(itemsOnly.map(n => n.data_groupId || null));
        const allSameExistingGroup = (distinctGroupIds.size === 1 && !distinctGroupIds.has(null));
        const canGroup = itemsOnly.length >= 2 && !allSameExistingGroup;
        const canUngroup = tr.nodes().some(n => n.data_deviceid === 'group' || n.data_groupId);
        createMenuItem('groupMenuDiv',   'Group',   'ctrl+g',       !canGroup);
        createMenuItem('ungroupMenuDiv', 'Ungroup', 'ctrl+shift+g', !canUngroup);
        rightClickMenuDiv.appendChild(hr.cloneNode(true));
        createMenuItem('undoDiv', 'Undo', 'ctrl+z', !(undoArray.length > 1));
        createMenuItem('redoDiv', 'Redo', 'ctrl+y', !(redoArray.length > 0));
    }




    rightClickMenuDialog.style.top = newY + 'px'; /* Distance from the top of the viewport, moved to center */
    rightClickMenuDialog.style.left = newX + 'px';

    rightClickMenuDialogLastPosition.x = newX;
    rightClickMenuDialogLastPosition.y = newY;

    rightClickMenuDialog.style.position = 'fixed';


    rightClickMenuDiv.addEventListener('mouseenter', function (event) {
        mouseOverRightClickMenu = true;

    });

    rightClickMenuDiv.addEventListener('mouseleave', function (event) {
        mouseOverRightClickMenu = false;

    });

    /* recreate menu on second right click */
    rightClickMenuDialog.addEventListener('contextmenu', function (event) {
        event.preventDefault();

        if (mouseUnit.x < 0 || mouseUnit.y < 0) {
            rightClickMenuDialog.close();
            return;
        }

        createRightClickMenu();

    });


    function createMenuItem(menuId, menuText, shortCut, disableDiv = false) {
        let mainDivClass = 'rightClickMenuItem';

        if (disableDiv) {
            mainDivClass = 'rightClickMenuItemDisable';
            menuId = menuId + 'Disable';
        }

        let menuItem = document.createElement('div');
        menuItem.id = menuId;
        menuItem.className = mainDivClass;
        menuItem.textContent = menuText;
        rightClickMenuDiv.appendChild(menuItem);

        let shortCutSpan = document.createElement('span');
        shortCutSpan.id = menuId + 'shortCut';
        shortCutSpan.className = 'rightClickMenuShortCutText';
        shortCutSpan.textContent = shortCut;
        menuItem.appendChild(shortCutSpan);

        menuItem.addEventListener('click', function menuItemClick(e) {

            closeRightClickMenu();
            if (e.target.id === 'copyMenuDiv') {
                copyItems();
            }
            else if (e.target.id === 'deleteMenuDiv') {
                deleteTrNodes();
            }
            else if (e.target.id === 'pasteMenuDiv') {
                pasteItems(false);
            }
            else if (e.target.id === 'duplicateMenuDiv') {
                duplicateItems();
            }
            else if (e.target.id === 'zoomResetDiv') {
                zoomInOut('reset');
            }
            else if (e.target.id === 'undoDiv') {
                btnUndoClicked();
            }
            else if (e.target.id === 'redoDiv') {
                btnRedoClicked();
            }
            else if (e.target.id === 'quickAddMenu') {
                toggleQuickAdd(true);
            }
            else if (e.target.id === 'rotateDiv') {
                rotateTrNodeItems();

                tr.nodes().forEach(node => {
                    updateShading(node);
                });

                if (tr.nodes().length === 1) {
                    updateFormatDetails(shape.id());
                }
            }
            else if (e.target.id === 'groupMenuDiv') {
                createGroup();
            }
            else if (e.target.id === 'ungroupMenuDiv') {
                ungroupSelectedItems();
            }
        });


    }

}

